export interface Chapter {
  id: number;
  title: string;
  pageStart?: number; // Optional, AI estimated
  pageEnd?: number;   // Optional, AI estimated
  description?: string;
}

export interface BookStructure {
  id: string; // Unique ID for the book in library
  title: string;
  author: string;
  chapters: Chapter[];
  bookmarks: number[]; // Array of chapter IDs
}

export interface Concept {
  term: string;
  definition: string;
  visualPrompt: string;
}

export interface DictionaryEntry {
  word: string;
  context: string;
  definition: string;
}

export interface PodcastState {
  audioUrl: string | null;
  isLoading: boolean;
  script: string | null;
}

export interface VisualState {
  concepts: Concept[];
  generatedImages: Record<string, string>; // term -> base64/url
  isLoading: boolean;
}

export interface DictionaryState {
  entries: DictionaryEntry[];
  isLoading: boolean;
}

export interface VideoState {
  videoUrl: string | null;
  isLoading: boolean;
  progressMessage: string;
}

export interface FileContext {
  content: string; // Base64 string for PDF, or raw text string for text files
  mimeType: string;
  isText: boolean; // Flag to determine how to send to Gemini
}

export interface NotebookItem {
  id: string;
  text: string;
  type: 'word' | 'sentence';
  definition?: string;
  timestamp: number;
  sourceChapter?: string;
  bookTitle?: string;
  bookAuthor?: string;
  comment?: string;
  contextSource?: string; // e.g. "Neural_Podcast", "Input_Stream", "Decoded_Layer"
}

export enum AppView {
  UPLOAD = 'UPLOAD',
  DASHBOARD = 'DASHBOARD'
}

export enum Tab {
  AUDIOBOOK = 'AUDIOBOOK',
  DICTIONARY = 'DICTIONARY',
  CONCEPTS = 'CONCEPTS',
  PODCAST = 'PODCAST',
  ANIMATION = 'ANIMATION',
  NOTEBOOK = 'NOTEBOOK'
}

export type ThemeColor = 'indigo' | 'emerald' | 'rose' | 'amber' | 'cyan';

export interface AppSettings {
  targetLanguage: string;
  highlightColor: ThemeColor;
  textSize: 'sm' | 'base' | 'lg' | 'xl';
  lineHeight: 'tight' | 'normal' | 'relaxed' | 'loose';
  letterSpacing: 'tighter' | 'normal' | 'wide' | 'wider';
  font: 'Inter' | 'Merriweather' | 'Playfair Display' | 'Roboto Mono' | 'Open Sans' | 'Orbitron' | 'Cinzel' | 'Source Code Pro' | 'Crimson Text';
}

export interface LibraryItem {
  book: BookStructure;
  fileContext: FileContext;
  uploadDate: number;
}

import React, { useState } from 'react';
import { Upload, BookOpen, Headphones, Image as ImageIcon, BookA, Film, Menu, X, ChevronRight, FileText, Mic2, Settings as SettingsIcon, Library as LibraryIcon, Tag, Bookmark, Cpu, Notebook as NotebookIcon, Terminal, Activity, Database, Shield } from 'lucide-react';
import JSZip from 'jszip';
import { BookStructure, Chapter, AppView, Tab, FileContext, AppSettings, LibraryItem, NotebookItem } from './types';
import { analyzeBookStructure } from './services/gemini';
import { PodcastPlayer } from './components/PodcastPlayer';
import { Visualizer } from './components/Visualizer';
import { VideoSummary } from './components/VideoSummary';
import { AudioBook } from './components/AudioBook';
import { Notebook } from './components/Notebook';
import { Dictionary } from './components/Dictionary';
import { SettingsModal } from './components/SettingsModal';
import { GlobalContextLayer } from './components/GlobalContextLayer';
import { Loader } from './components/ui/Loader';
import { AIAssistant } from './components/AIAssistant';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.UPLOAD);

  const [library, setLibrary] = useState<LibraryItem[]>([]);
  const [activeBookId, setActiveBookId] = useState<string | null>(null);

  // Notebook State
  const [notebook, setNotebook] = useState<NotebookItem[]>([]);

  const activeBook = library.find(item => item.book.id === activeBookId)?.book || null;
  const activeFileContext = library.find(item => item.book.id === activeBookId)?.fileContext || null;

  const [activeChapterId, setActiveChapterId] = useState<number | null>(null);
  const activeChapter = activeBook?.chapters.find(c => c.id === activeChapterId) || null;

  const [activeTab, setActiveTab] = useState<Tab>(Tab.AUDIOBOOK);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showLibraryList, setShowLibraryList] = useState(false);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    targetLanguage: 'Spanish',
    highlightColor: 'indigo',
    textSize: 'base',
    lineHeight: 'normal',
    letterSpacing: 'normal',
    font: 'Inter'
  });

  const handleAddToNotebook = (item: Omit<NotebookItem, 'id' | 'timestamp'>) => {
      const newItem: NotebookItem = {
          ...item,
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          sourceChapter: activeChapter?.title,
          bookTitle: activeBook?.title,
          bookAuthor: activeBook?.author
      };
      setNotebook(prev => [newItem, ...prev]);
  };

  const handleDeleteNotebookItem = (id: string) => {
      setNotebook(prev => prev.filter(i => i.id !== id));
  };

  const handleBulkDeleteNotebookItems = (ids: string[]) => {
      setNotebook(prev => prev.filter(i => !ids.includes(i.id)));
  };

  const handleUpdateNotebookComment = (id: string, comment: string) => {
      setNotebook(prev => prev.map(item => item.id === id ? { ...item, comment } : item));
  };

  const processEpub = async (file: File): Promise<string> => {
    try {
      const zip = await JSZip.loadAsync(file);
      let fullText = "";
      const contentFiles = Object.keys(zip.files).filter(filename => 
        filename.match(/\.(html|xhtml|htm)$/i) && !filename.includes('__MACOSX')
      );
      contentFiles.sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
      const parser = new DOMParser();
      for (const filename of contentFiles) {
        const content = await zip.files[filename].async("string");
        const doc = parser.parseFromString(content, "text/html");
        fullText += (doc.body.textContent || "") + "\n\n";
      }
      if (!fullText) throw new Error("No readable text found in EPUB.");
      if (fullText.length > 100000) {
        return fullText.substring(0, 100000) + "... [Truncated]";
      }
      return fullText;
    } catch (e) {
      console.error("EPUB processing error", e);
      throw new Error("Could not parse EPUB file.");
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const allowedExtensions = ['.pdf', '.txt', '.md', '.html', '.xml', '.epub'];
    const hasAllowedExt = allowedExtensions.some(ext => file.name.toLowerCase().endsWith(ext));

    if (!hasAllowedExt) {
      setError("Supported formats: PDF, EPUB, TXT, MD, HTML.");
      return;
    }

    setIsProcessing(true);
    setError(null);

    const reader = new FileReader();
    const isEpub = file.name.toLowerCase().endsWith('.epub');
    const isTextBased = file.type.startsWith('text/') || 
                        ['.txt', '.md', '.html', '.xml'].some(ext => file.name.toLowerCase().endsWith(ext));

    const finalizeUpload = async (context: FileContext) => {
        try {
            const structure = await analyzeBookStructure(context);
            const newItem: LibraryItem = {
                book: structure,
                fileContext: context,
                uploadDate: Date.now()
            };
            setLibrary(prev => [newItem, ...prev]);
            setActiveBookId(structure.id);
            if (structure.chapters.length > 0) setActiveChapterId(structure.chapters[0].id);
            setView(AppView.DASHBOARD);
            setShowLibraryList(false);
        } catch (err: any) {
            setError("Analysis failed. " + err.message);
        } finally {
            setIsProcessing(false);
        }
    };

    if (isEpub) {
       try {
         const textContent = await processEpub(file);
         await finalizeUpload({
            content: textContent,
            mimeType: 'text/plain',
            isText: true
         });
       } catch (err: any) {
         setError(err.message || "Failed to process EPUB.");
         setIsProcessing(false);
       }
       return;
    }

    reader.onload = async (e) => {
      let context: FileContext;
      if (isTextBased) {
          let content = e.target?.result as string;
          if (content.length > 100000) content = content.substring(0, 100000) + "... [Truncated]";
          context = { content, mimeType: 'text/plain', isText: true };
      } else {
          const base64 = (e.target?.result as string).split(',')[1];
          context = { content: base64, mimeType: 'application/pdf', isText: false };
      }
      await finalizeUpload(context);
    };

    if (isTextBased) reader.readAsText(file);
    else reader.readAsDataURL(file);
  };

  const toggleBookmark = (chapterId: number) => {
    if (!activeBookId) return;
    setLibrary(prev => prev.map(item => {
        if (item.book.id === activeBookId) {
            const bookmarks = item.book.bookmarks || [];
            const isBookmarked = bookmarks.includes(chapterId);
            const newBookmarks = isBookmarked 
                ? bookmarks.filter(id => id !== chapterId)
                : [...bookmarks, chapterId];
            return { ...item, book: { ...item.book, bookmarks: newBookmarks } };
        }
        return item;
    }));
  };

  const renderContent = () => {
    // Notebook is global, doesn't need active chapter
    if (activeTab === Tab.NOTEBOOK) {
        return <Notebook 
          items={notebook} 
          onDelete={handleDeleteNotebookItem} 
          onBulkDelete={handleBulkDeleteNotebookItems}
          onUpdateComment={handleUpdateNotebookComment} 
          settings={settings} 
        />;
    }

    if (!activeChapter || !activeFileContext) return null;

    let content;
    switch (activeTab) {
      case Tab.AUDIOBOOK:
        content = <AudioBook chapter={activeChapter} fileContext={activeFileContext} settings={settings} onSettingsUpdate={setSettings} />;
        break;
      case Tab.DICTIONARY:
        content = <Dictionary chapter={activeChapter} fileContext={activeFileContext} settings={settings} />;
        break;
      case Tab.PODCAST:
        content = <PodcastPlayer chapter={activeChapter} fileContext={activeFileContext} settings={settings} />;
        break;
      case Tab.CONCEPTS:
        content = <Visualizer chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      case Tab.ANIMATION:
        content = <VideoSummary chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      default:
        content = null;
    }

    return (
      <div key={`${activeBookId}-${activeChapter.id}-${activeTab}`} className="h-full animate-fade-in">
        {content}
      </div>
    );
  };

  if (view === AppView.UPLOAD) {
    return (
      <div className="min-h-screen bg-[#020202] bg-grid flex flex-col items-center justify-center p-6 relative overflow-hidden font-tech">

        {/* Decor: Corners */}
        <div className="absolute top-8 left-8 w-24 h-24 border-l border-t border-zinc-800 rounded-tl-lg pointer-events-none"></div>
        <div className="absolute bottom-8 right-8 w-24 h-24 border-r border-b border-zinc-800 rounded-br-lg pointer-events-none"></div>

        <div className="z-10 max-w-lg w-full text-center space-y-12">
          <div className="space-y-2 animate-fade-in-up">
             <div className="flex items-center justify-center gap-2 mb-4">
                <Terminal size={32} className="text-[#00f3ff]" />
             </div>
            <h1 className="text-7xl font-bold tracking-tighter text-white drop-shadow-[0_0_25px_rgba(0,243,255,0.3)]">
              Decod<span className="text-[#00f3ff]">Ebook</span>
            </h1>
            <p className="text-zinc-500 tracking-[0.2em] text-xs uppercase">
              V.4.2 // Neural Text Decoding Interface
            </p>
          </div>

          <div className="relative group animate-fade-in-up hud-border bg-[#050505] p-10 transition-all duration-500 hover:shadow-[0_0_30px_rgba(0,243,255,0.1)]" style={{ animationDelay: '0.1s' }}>

              {isProcessing ? (
                <Loader text="DECODING_SOURCE..." />
              ) : (
                <div className="relative flex flex-col items-center justify-center space-y-8">
                  <div className="relative">
                    <div className="w-32 h-32 bg-[#0a0a0c] border border-zinc-800 rounded-full flex items-center justify-center group-hover:border-[#00f3ff] transition-all duration-500">
                        <Upload className="w-12 h-12 text-zinc-600 group-hover:text-[#00f3ff] transition-colors" />
                    </div>
                    {/* Ring Animation */}
                    <div className="absolute -inset-2 border border-dashed border-zinc-800 rounded-full animate-spin-slow pointer-events-none group-hover:border-[#00f3ff]/30"></div>
                  </div>

                  <div className="space-y-2">
                    <p className="text-[#00f3ff] font-bold uppercase tracking-widest text-sm animate-pulse">Initialize Upload</p>
                    <p className="text-[10px] text-zinc-600 font-mono">SUPPORTED PROTOCOLS: PDF / EPUB / TXT / MD</p>
                  </div>

                  <input 
                    type="file" 
                    accept=".pdf,.txt,.md,.html,.xml,.epub"
                    onChange={handleFileUpload}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                </div>
              )}
          </div>

          {library.length > 0 && (
             <button 
                onClick={() => setView(AppView.DASHBOARD)}
                className="text-zinc-500 hover:text-[#00f3ff] text-xs font-mono uppercase tracking-widest transition-colors flex items-center gap-2 mx-auto border border-transparent hover:border-[#00f3ff]/30 px-4 py-2 rounded-sm"
             >
                <LibraryIcon size={14} />
                Access_Data_Bank [{library.length}]
             </button>
          )}
          {error && <p className="text-[#ff003c] text-xs font-mono border border-[#ff003c]/30 p-2 bg-[#ff003c]/5">{error}</p>}
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#020202] bg-grid text-zinc-300 overflow-hidden font-sans relative">
      <GlobalContextLayer onAddToNotebook={handleAddToNotebook} activeLanguage={settings.targetLanguage} />

      {/* Floating Chat Assistant - Now with smart ID tracking */}
      <AIAssistant 
        fileContext={activeFileContext} 
        bookTitle={activeBook?.title} 
        bookId={activeBook?.id} 
      />

      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        settings={settings}
        onUpdate={setSettings}
      />

      {/* Sidebar: Server Rack Style */}
      <aside 
        className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-[#050505] flex flex-col overflow-hidden relative z-20 transition-all duration-300 border-r border-zinc-900`}
      >
        <div className="p-4 border-b border-zinc-900 shrink-0 bg-black/80 backdrop-blur-sm relative overflow-hidden">
            {/* Header Glitch Bar */}
            <div className="absolute top-0 left-0 w-full h-[1px] bg-[#00f3ff] opacity-20"></div>

            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2">
                    <Cpu size={16} className="text-[#00f3ff]" />
                    <span className="text-xs font-tech font-bold text-white tracking-[0.2em]">DECOD.EBOOK</span>
                </div>
                <button 
                    onClick={() => setView(AppView.UPLOAD)} 
                    className="p-1.5 rounded-sm hover:bg-zinc-900 text-zinc-600 hover:text-[#00f3ff] transition-colors"
                    title="Upload New"
                >
                    <Upload size={14} />
                </button>
            </div>

            <div className="flex items-center justify-between mb-2">
                <button 
                onClick={() => setShowLibraryList(!showLibraryList)}
                className={`flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest transition-colors font-tech border px-2 py-1 rounded-sm w-full justify-between ${showLibraryList ? 'text-[#00f3ff] border-[#00f3ff]/50' : 'text-zinc-500 border-zinc-900 hover:border-zinc-700 hover:text-white'}`}
                >
                    <span className="flex items-center gap-2"><Database size={10} /> {showLibraryList ? "SESSION_DATA" : "DATA_BANKS"}</span>
                    <span className="text-[8px] animate-pulse">●</span>
                </button>
            </div>

            {!showLibraryList && activeBook && (
                <div className="mt-4 p-3 border border-zinc-800 bg-zinc-900/20 rounded-sm relative group cursor-default">
                    {/* Corner accent */}
                    <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-[#00f3ff]"></div>
                    <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-[#00f3ff]"></div>

                    <h1 className="font-bold text-xs text-white truncate leading-tight mb-1 font-tech uppercase tracking-wide">{activeBook.title}</h1>
                    <p className="text-[9px] text-zinc-500 truncate font-mono uppercase">{activeBook.author}</p>
                    <div className="mt-2 text-[9px] text-[#00f3ff] font-mono flex items-center gap-1">
                        <Activity size={10} /> SYS.ACTIVE
                    </div>
                </div>
            )}
        </div>

        <div className="flex-1 overflow-y-auto p-0 custom-scrollbar">
          {showLibraryList ? (
             <div className="flex flex-col">
                {library.map(item => (
                    <button
                        key={item.book.id}
                        onClick={() => {
                            setActiveBookId(item.book.id);
                            if(item.book.chapters.length > 0) setActiveChapterId(item.book.chapters[0].id);
                            setShowLibraryList(false);
                        }}
                        className={`w-full flex items-center gap-3 p-4 border-b border-zinc-900 transition-all group ${
                            activeBookId === item.book.id 
                            ? 'bg-[#00f3ff]/5' 
                            : 'hover:bg-zinc-900'
                        }`}
                    >
                        <div className={`w-1 h-8 ${activeBookId === item.book.id ? 'bg-[#00f3ff]' : 'bg-zinc-800'}`}></div>
                        <div className="text-left min-w-0">
                            <h4 className={`text-[10px] font-bold truncate font-tech uppercase tracking-wide ${activeBookId === item.book.id ? 'text-[#00f3ff]' : 'text-zinc-400'}`}>
                                {item.book.title}
                            </h4>
                            <p className="text-[9px] text-zinc-600 truncate font-mono">{item.book.chapters.length} DATA_BLOCKS</p>
                        </div>
                    </button>
                ))}
             </div>
          ) : (
             <div className="py-2">
                {activeBook?.chapters.map((chapter, idx) => {
                    const isBookmarked = activeBook.bookmarks?.includes(chapter.id);
                    return (
                        <div key={chapter.id} className="relative group flex items-center justify-between px-4 py-2 hover:bg-zinc-900/50">
                            <button
                                onClick={() => setActiveChapterId(chapter.id)}
                                className={`flex-1 text-left flex items-center gap-3 border-l-2 py-1 transition-all min-w-0 pr-2 ${
                                    activeChapterId === chapter.id 
                                    ? 'border-[#00f3ff]' 
                                    : 'border-transparent'
                                }`}
                            >
                                <span className={`text-[9px] font-mono w-6 text-right shrink-0 ${activeChapterId === chapter.id ? 'text-[#00f3ff]' : 'text-zinc-700'}`}>
                                    {String(idx + 1).padStart(2, '0')}
                                </span>
                                <div className="min-w-0 flex-1">
                                    <p className={`font-medium truncate font-tech uppercase tracking-tight text-xs ${activeChapterId === chapter.id ? 'text-white' : 'text-zinc-500'}`}>
                                        {chapter.title}
                                    </p>
                                </div>
                            </button>
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleBookmark(chapter.id); }}
                                className={`p-1.5 transition-colors shrink-0 ${isBookmarked ? 'text-amber-400' : 'text-zinc-800 hover:text-zinc-500'}`}
                                title={isBookmarked ? "Remove Bookmark" : "Add Bookmark"}
                            >
                                <Tag size={12} fill={isBookmarked ? "currentColor" : "none"} />
                            </button>
                        </div>
                    );
                })}
             </div>
          )}
        </div>

        <div className="p-0 border-t border-zinc-900 bg-black">
          <button 
            onClick={() => setIsSettingsOpen(true)}
            className="w-full flex items-center gap-3 p-4 hover:bg-zinc-900 text-zinc-500 hover:text-[#00f3ff] transition-colors text-[10px] font-bold font-tech uppercase tracking-widest"
          >
            <SettingsIcon size={14} />
            <span>SYS_CONFIG</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 relative bg-transparent z-10">

        {/* Header Status Bar */}
        <header className="h-14 border-b border-zinc-900 flex items-center justify-between px-4 bg-black/90 backdrop-blur-md sticky top-0 z-30 shrink-0">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="text-zinc-500 hover:text-[#00f3ff] transition-colors">
              {isSidebarOpen ? <X size={18} /> : <Menu size={18} />}
            </button>
            <div className="h-4 w-[1px] bg-zinc-800 mx-1"></div>

            {activeChapterId ? (
                <div className="flex items-center gap-2">
                    <span className="text-[9px] font-mono text-zinc-600 bg-zinc-900 border border-zinc-800 px-1.5 py-0.5">
                        SEC.{String(activeChapterId || 0).padStart(2, '0')}
                    </span>
                    <ChevronRight size={12} className="text-zinc-700" />
                    <span className="text-xs font-bold text-[#00f3ff] font-tech tracking-wide truncate max-w-[200px]">
                        {activeChapter?.title.toUpperCase()}
                    </span>
                </div>
            ) : (
                <span className="text-xs font-tech text-zinc-500 tracking-widest">AWAITING_INPUT</span>
            )}
          </div>

          {/* Module Selector */}
          <div className="flex items-center bg-zinc-950 border border-zinc-900 p-0.5 rounded-sm">
            {[
              { id: Tab.AUDIOBOOK, icon: Headphones, label: "VOICE_SYNTH" },
              { id: Tab.DICTIONARY, icon: BookA, label: "LEXICON" },
              { id: Tab.CONCEPTS, icon: ImageIcon, label: "VISUAL_CORE" },
              { id: Tab.PODCAST, icon: Mic2, label: "NET_CAST" },
              { id: Tab.ANIMATION, icon: Film, label: "CINE_RENDER" },
              { id: Tab.NOTEBOOK, icon: NotebookIcon, label: "MEM_LOG" },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex items-center gap-2 px-3 py-1.5 transition-all text-[9px] font-bold uppercase tracking-wider font-tech ${
                  activeTab === tab.id 
                    ? 'bg-[#00f3ff]/10 text-[#00f3ff] shadow-[0_0_10px_rgba(0,243,255,0.1)]'
                    : 'text-zinc-600 hover:text-zinc-300 hover:bg-zinc-900'
                }`}
              >
                <tab.icon size={12} className={activeTab === tab.id ? 'text-[#00f3ff]' : ''} />
                <span className="hidden xl:inline">{tab.label}</span>
              </button>
            ))}
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 p-0 overflow-hidden relative">
          <div className="h-full w-full p-6 overflow-y-auto custom-scrollbar">
             {renderContent()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Upload, BookOpen, Headphones, Image as ImageIcon, BookA, Film, Menu, X, ChevronRight, FileText, Mic2, Settings as SettingsIcon, Library as LibraryIcon, Tag, Bookmark, Cpu, Notebook as NotebookIcon, Terminal, Activity, Database, Shield } from 'lucide-react';
import JSZip from 'jszip';
import { BookStructure, Chapter, AppView, Tab, FileContext, AppSettings, LibraryItem, NotebookItem } from './types';
import { analyzeBookStructure } from './services/gemini';
import { PodcastPlayer } from './components/PodcastPlayer';
import { Visualizer } from './components/Visualizer';
import { VideoSummary } from './components/VideoSummary';
import { AudioBook } from './components/AudioBook';
import { Notebook } from './components/Notebook';
import { Dictionary } from './components/Dictionary';
import { SettingsModal } from './components/SettingsModal';
import { GlobalContextLayer } from './components/GlobalContextLayer';
import { Loader } from './components/ui/Loader';
import { AIAssistant } from './components/AIAssistant';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.UPLOAD);

  const [library, setLibrary] = useState<LibraryItem[]>([]);
  const [activeBookId, setActiveBookId] = useState<string | null>(null);

  // Notebook State
  const [notebook, setNotebook] = useState<NotebookItem[]>([]);

  const activeBook = library.find(item => item.book.id === activeBookId)?.book || null;
  const activeFileContext = library.find(item => item.book.id === activeBookId)?.fileContext || null;

  const [activeChapterId, setActiveChapterId] = useState<number | null>(null);
  const activeChapter = activeBook?.chapters.find(c => c.id === activeChapterId) || null;

  const [activeTab, setActiveTab] = useState<Tab>(Tab.AUDIOBOOK);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showLibraryList, setShowLibraryList] = useState(false);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    targetLanguage: 'Spanish',
    highlightColor: 'indigo',
    textSize: 'base',
    lineHeight: 'normal',
    letterSpacing: 'normal',
    font: 'Inter'
  });

  const handleAddToNotebook = (item: Omit<NotebookItem, 'id' | 'timestamp'>) => {
      const newItem: NotebookItem = {
          ...item,
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          sourceChapter: activeChapter?.title,
          bookTitle: activeBook?.title,
          bookAuthor: activeBook?.author
      };
      setNotebook(prev => [newItem, ...prev]);
  };

  const handleDeleteNotebookItem = (id: string) => {
      setNotebook(prev => prev.filter(i => i.id !== id));
  };

  const handleBulkDeleteNotebookItems = (ids: string[]) => {
      setNotebook(prev => prev.filter(i => !ids.includes(i.id)));
  };

  const handleUpdateNotebookComment = (id: string, comment: string) => {
      setNotebook(prev => prev.map(item => item.id === id ? { ...item, comment } : item));
  };

  const processEpub = async (file: File): Promise<string> => {
    try {
      const zip = await JSZip.loadAsync(file);
      let fullText = "";
      const contentFiles = Object.keys(zip.files).filter(filename => 
        filename.match(/\.(html|xhtml|htm)$/i) && !filename.includes('__MACOSX')
      );
      contentFiles.sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
      const parser = new DOMParser();
      for (const filename of contentFiles) {
        const content = await zip.files[filename].async("string");
        const doc = parser.parseFromString(content, "text/html");
        fullText += (doc.body.textContent || "") + "\n\n";
      }
      if (!fullText) throw new Error("No readable text found in EPUB.");
      if (fullText.length > 100000) {
        return fullText.substring(0, 100000) + "... [Truncated]";
      }
      return fullText;
    } catch (e) {
      console.error("EPUB processing error", e);
      throw new Error("Could not parse EPUB file.");
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const allowedExtensions = ['.pdf', '.txt', '.md', '.html', '.xml', '.epub'];
    const hasAllowedExt = allowedExtensions.some(ext => file.name.toLowerCase().endsWith(ext));

    if (!hasAllowedExt) {
      setError("Supported formats: PDF, EPUB, TXT, MD, HTML.");
      return;
    }

    setIsProcessing(true);
    setError(null);

    const reader = new FileReader();
    const isEpub = file.name.toLowerCase().endsWith('.epub');
    const isTextBased = file.type.startsWith('text/') || 
                        ['.txt', '.md', '.html', '.xml'].some(ext => file.name.toLowerCase().endsWith(ext));

    const finalizeUpload = async (context: FileContext) => {
        try {
            const structure = await analyzeBookStructure(context);
            const newItem: LibraryItem = {
                book: structure,
                fileContext: context,
                uploadDate: Date.now()
            };
            setLibrary(prev => [newItem, ...prev]);
            setActiveBookId(structure.id);
            if (structure.chapters.length > 0) setActiveChapterId(structure.chapters[0].id);
            setView(AppView.DASHBOARD);
            setShowLibraryList(false);
        } catch (err: any) {
            setError("Analysis failed. " + err.message);
        } finally {
            setIsProcessing(false);
        }
    };

    if (isEpub) {
       try {
         const textContent = await processEpub(file);
         await finalizeUpload({
            content: textContent,
            mimeType: 'text/plain',
            isText: true
         });
       } catch (err: any) {
         setError(err.message || "Failed to process EPUB.");
         setIsProcessing(false);
       }
       return;
    }

    reader.onload = async (e) => {
      let context: FileContext;
      if (isTextBased) {
          let content = e.target?.result as string;
          if (content.length > 100000) content = content.substring(0, 100000) + "... [Truncated]";
          context = { content, mimeType: 'text/plain', isText: true };
      } else {
          const base64 = (e.target?.result as string).split(',')[1];
          context = { content: base64, mimeType: 'application/pdf', isText: false };
      }
      await finalizeUpload(context);
    };

    if (isTextBased) reader.readAsText(file);
    else reader.readAsDataURL(file);
  };

  const toggleBookmark = (chapterId: number) => {
    if (!activeBookId) return;
    setLibrary(prev => prev.map(item => {
        if (item.book.id === activeBookId) {
            const bookmarks = item.book.bookmarks || [];
            const isBookmarked = bookmarks.includes(chapterId);
            const newBookmarks = isBookmarked 
                ? bookmarks.filter(id => id !== chapterId)
                : [...bookmarks, chapterId];
            return { ...item, book: { ...item.book, bookmarks: newBookmarks } };
        }
        return item;
    }));
  };

  const renderContent = () => {
    // Notebook is global, doesn't need active chapter
    if (activeTab === Tab.NOTEBOOK) {
        return <Notebook 
          items={notebook} 
          onDelete={handleDeleteNotebookItem} 
          onBulkDelete={handleBulkDeleteNotebookItems}
          onUpdateComment={handleUpdateNotebookComment} 
          settings={settings} 
        />;
    }

    if (!activeChapter || !activeFileContext) return null;

    let content;
    switch (activeTab) {
      case Tab.AUDIOBOOK:
        content = <AudioBook chapter={activeChapter} fileContext={activeFileContext} settings={settings} onSettingsUpdate={setSettings} />;
        break;
      case Tab.DICTIONARY:
        content = <Dictionary chapter={activeChapter} fileContext={activeFileContext} settings={settings} />;
        break;
      case Tab.CONCEPTS:
        content = <Visualizer chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      case Tab.PODCAST:
        content = <PodcastPlayer chapter={activeChapter} fileContext={activeFileContext} settings={settings} />;
        break;
      case Tab.ANIMATION:
        content = <VideoSummary chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      default:
        content = null;
    }

    return (
      <div key={`${activeBookId}-${activeChapter.id}-${activeTab}`} className="h-full animate-fade-in">
        {content}
      </div>
    );
  };

  if (view === AppView.UPLOAD) {
    return (
      <div className="min-h-screen bg-[#020202] bg-grid flex flex-col items-center justify-center p-6 relative overflow-hidden font-tech">

        {/* Decor: Corners */}
        <div className="absolute top-8 left-8 w-24 h-24 border-l border-t border-zinc-800 rounded-tl-lg pointer-events-none"></div>
        <div className="absolute bottom-8 right-8 w-24 h-24 border-r border-b border-zinc-800 rounded-br-lg pointer-events-none"></div>

        <div className="z-10 max-w-lg w-full text-center space-y-12">
          <div className="space-y-2 animate-fade-in-up">
             <div className="flex items-center justify-center gap-2 mb-4">
                <Terminal size={32} className="text-[#00f3ff]" />
             </div>
            <h1 className="text-7xl font-bold tracking-tighter text-white drop-shadow-[0_0_25px_rgba(0,243,255,0.3)]">
              Decod<span className="text-[#00f3ff]">Ebook</span>
            </h1>
            <p className="text-zinc-500 tracking-[0.2em] text-xs uppercase">
              V.4.2 // Neural Text Decoding Interface
            </p>
          </div>

          <div className="relative group animate-fade-in-up hud-border bg-[#050505] p-10 transition-all duration-500 hover:shadow-[0_0_30px_rgba(0,243,255,0.1)]" style={{ animationDelay: '0.1s' }}>

              {isProcessing ? (
                <Loader text="DECODING_SOURCE..." />
              ) : (
                <div className="relative flex flex-col items-center justify-center space-y-8">
                  <div className="relative">
                    <div className="w-32 h-32 bg-[#0a0a0c] border border-zinc-800 rounded-full flex items-center justify-center group-hover:border-[#00f3ff] transition-all duration-500">
                        <Upload className="w-12 h-12 text-zinc-600 group-hover:text-[#00f3ff] transition-colors" />
                    </div>
                    {/* Ring Animation */}
                    <div className="absolute -inset-2 border border-dashed border-zinc-800 rounded-full animate-spin-slow pointer-events-none group-hover:border-[#00f3ff]/30"></div>
                  </div>

                  <div className="space-y-2">
                    <p className="text-[#00f3ff] font-bold uppercase tracking-widest text-sm animate-pulse">Initialize Upload</p>
                    <p className="text-[10px] text-zinc-600 font-mono">SUPPORTED PROTOCOLS: PDF / EPUB / TXT / MD</p>
                  </div>

                  <input 
                    type="file" 
                    accept=".pdf,.txt,.md,.html,.xml,.epub"
                    onChange={handleFileUpload}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                </div>
              )}
          </div>

          {library.length > 0 && (
             <button 
                onClick={() => setView(AppView.DASHBOARD)}
                className="text-zinc-500 hover:text-[#00f3ff] text-xs font-mono uppercase tracking-widest transition-colors flex items-center gap-2 mx-auto border border-transparent hover:border-[#00f3ff]/30 px-4 py-2 rounded-sm"
             >
                <LibraryIcon size={14} />
                Access_Data_Bank [{library.length}]
             </button>
          )}
          {error && <p className="text-[#ff003c] text-xs font-mono border border-[#ff003c]/30 p-2 bg-[#ff003c]/5">{error}</p>}
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#020202] bg-grid text-zinc-300 overflow-hidden font-sans relative">
      <GlobalContextLayer onAddToNotebook={handleAddToNotebook} activeLanguage={settings.targetLanguage} />

      {/* Floating Chat Assistant - Now with smart ID tracking */}
      <AIAssistant 
        fileContext={activeFileContext} 
        bookTitle={activeBook?.title} 
        bookId={activeBook?.id} 
      />

      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        settings={settings}
        onUpdate={setSettings}
      />

      {/* Sidebar: Server Rack Style */}
      <aside 
        className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-[#050505] flex flex-col overflow-hidden relative z-20 transition-all duration-300 border-r border-zinc-900`}
      >
        <div className="p-4 border-b border-zinc-900 shrink-0 bg-black/80 backdrop-blur-sm relative overflow-hidden">
            {/* Header Glitch Bar */}
            <div className="absolute top-0 left-0 w-full h-[1px] bg-[#00f3ff] opacity-20"></div>

            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2">
                    <Cpu size={16} className="text-[#00f3ff]" />
                    <span className="text-xs font-tech font-bold text-white tracking-[0.2em]">DECOD.EBOOK</span>
                </div>
                <button 
                    onClick={() => setView(AppView.UPLOAD)} 
                    className="p-1.5 rounded-sm hover:bg-zinc-900 text-zinc-600 hover:text-[#00f3ff] transition-colors"
                    title="Upload New"
                >
                    <Upload size={14} />
                </button>
            </div>

            <div className="flex items-center justify-between mb-2">
                <button 
                onClick={() => setShowLibraryList(!showLibraryList)}
                className={`flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest transition-colors font-tech border px-2 py-1 rounded-sm w-full justify-between ${showLibraryList ? 'text-[#00f3ff] border-[#00f3ff]/50' : 'text-zinc-500 border-zinc-900 hover:border-zinc-700 hover:text-white'}`}
                >
                    <span className="flex items-center gap-2"><Database size={10} /> {showLibraryList ? "SESSION_DATA" : "DATA_BANKS"}</span>
                    <span className="text-[8px] animate-pulse">●</span>
                </button>
            </div>

            {!showLibraryList && activeBook && (
                <div className="mt-4 p-3 border border-zinc-800 bg-zinc-900/20 rounded-sm relative group cursor-default">
                    {/* Corner accent */}
                    <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-[#00f3ff]"></div>
                    <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-[#00f3ff]"></div>

                    <h1 className="font-bold text-xs text-white truncate leading-tight mb-1 font-tech uppercase tracking-wide">{activeBook.title}</h1>
                    <p className="text-[9px] text-zinc-500 truncate font-mono uppercase">{activeBook.author}</p>
                    <div className="mt-2 text-[9px] text-[#00f3ff] font-mono flex items-center gap-1">
                        <Activity size={10} /> SYS.ACTIVE
                    </div>
                </div>
            )}
        </div>

        <div className="flex-1 overflow-y-auto p-0 custom-scrollbar">
          {showLibraryList ? (
             <div className="flex flex-col">
                {library.map(item => (
                    <button
                        key={item.book.id}
                        onClick={() => {
                            setActiveBookId(item.book.id);
                            if(item.book.chapters.length > 0) setActiveChapterId(item.book.chapters[0].id);
                            setShowLibraryList(false);
                        }}
                        className={`w-full flex items-center gap-3 p-4 border-b border-zinc-900 transition-all group ${
                            activeBookId === item.book.id 
                            ? 'bg-[#00f3ff]/5' 
                            : 'hover:bg-zinc-900'
                        }`}
                    >
                        <div className={`w-1 h-8 ${activeBookId === item.book.id ? 'bg-[#00f3ff]' : 'bg-zinc-800'}`}></div>
                        <div className="text-left min-w-0">
                            <h4 className={`text-[10px] font-bold truncate font-tech uppercase tracking-wide ${activeBookId === item.book.id ? 'text-[#00f3ff]' : 'text-zinc-400'}`}>
                                {item.book.title}
                            </h4>
                            <p className="text-[9px] text-zinc-600 truncate font-mono">{item.book.chapters.length} DATA_BLOCKS</p>
                        </div>
                    </button>
                ))}
             </div>
          ) : (
             <div className="py-2">
                {activeBook?.chapters.map((chapter, idx) => {
                    const isBookmarked = activeBook.bookmarks?.includes(chapter.id);
                    return (
                        <div key={chapter.id} className="relative group flex items-center justify-between px-4 py-2 hover:bg-zinc-900/50">
                            <button
                                onClick={() => setActiveChapterId(chapter.id)}
                                className={`flex-1 text-left flex items-center gap-3 border-l-2 py-1 transition-all min-w-0 pr-2 ${
                                    activeChapterId === chapter.id 
                                    ? 'border-[#00f3ff]' 
                                    : 'border-transparent'
                                }`}
                            >
                                <span className={`text-[9px] font-mono w-6 text-right shrink-0 ${activeChapterId === chapter.id ? 'text-[#00f3ff]' : 'text-zinc-700'}`}>
                                    {String(idx + 1).padStart(2, '0')}
                                </span>
                                <div className="min-w-0 flex-1">
                                    <p className={`font-medium truncate font-tech uppercase tracking-tight text-xs ${activeChapterId === chapter.id ? 'text-white' : 'text-zinc-500'}`}>
                                        {chapter.title}
                                    </p>
                                </div>
                            </button>
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleBookmark(chapter.id); }}
                                className={`p-1.5 transition-colors shrink-0 ${isBookmarked ? 'text-amber-400' : 'text-zinc-800 hover:text-zinc-500'}`}
                                title={isBookmarked ? "Remove Bookmark" : "Add Bookmark"}
                            >
                                <Tag size={12} fill={isBookmarked ? "currentColor" : "none"} />
                            </button>
                        </div>
                    );
                })}
             </div>
          )}
        </div>

        <div className="p-0 border-t border-zinc-900 bg-black">
          <button 
            onClick={() => setIsSettingsOpen(true)}
            className="w-full flex items-center gap-3 p-4 hover:bg-zinc-900 text-zinc-500 hover:text-[#00f3ff] transition-colors text-[10px] font-bold font-tech uppercase tracking-widest"
          >
            <SettingsIcon size={14} />
            <span>SYS_CONFIG</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 relative bg-transparent z-10">

        {/* Header Status Bar */}
        <header className="h-14 border-b border-zinc-900 flex items-center justify-between px-4 bg-black/90 backdrop-blur-md sticky top-0 z-30 shrink-0">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="text-zinc-500 hover:text-[#00f3ff] transition-colors">
              {isSidebarOpen ? <X size={18} /> : <Menu size={18} />}
            </button>
            <div className="h-4 w-[1px] bg-zinc-800 mx-1"></div>

            {activeChapterId ? (
                <div className="flex items-center gap-2">
                    <span className="text-[9px] font-mono text-zinc-600 bg-zinc-900 border border-zinc-800 px-1.5 py-0.5">
                        SEC.{String(activeChapterId || 0).padStart(2, '0')}
                    </span>
                    <ChevronRight size={12} className="text-zinc-700" />
                    <span className="text-xs font-bold text-[#00f3ff] font-tech tracking-wide truncate max-w-[200px]">
                        {activeChapter?.title.toUpperCase()}
                    </span>
                </div>
            ) : (
                <span className="text-xs font-tech text-zinc-500 tracking-widest">AWAITING_INPUT</span>
            )}
          </div>

          {/* Module Selector */}
          <div className="flex items-center bg-zinc-950 border border-zinc-900 p-0.5 rounded-sm">
            {[
              { id: Tab.AUDIOBOOK, icon: Headphones, label: "VOICE_SYNTH" },
              { id: Tab.DICTIONARY, icon: BookA, label: "LEXICON" },
              { id: Tab.CONCEPTS, icon: ImageIcon, label: "VISUAL_CORE" },
              { id: Tab.PODCAST, icon: Mic2, label: "NET_CAST" },
              { id: Tab.ANIMATION, icon: Film, label: "CINE_RENDER" },
              { id: Tab.NOTEBOOK, icon: NotebookIcon, label: "MEM_LOG" },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex items-center gap-2 px-3 py-1.5 transition-all text-[9px] font-bold uppercase tracking-wider font-tech ${
                  activeTab === tab.id 
                    ? 'bg-[#00f3ff]/10 text-[#00f3ff] shadow-[0_0_10px_rgba(0,243,255,0.1)]'
                    : 'text-zinc-600 hover:text-zinc-300 hover:bg-zinc-900'
                }`}
              >
                <tab.icon size={12} className={activeTab === tab.id ? 'text-[#00f3ff]' : ''} />
                <span className="hidden xl:inline">{tab.label}</span>
              </button>
            ))}
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 p-0 overflow-hidden relative">
          <div className="h-full w-full p-6 overflow-y-auto custom-scrollbar">
             {renderContent()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Lightbulb, Image as ImageIcon, Download, RefreshCw, Settings2, Hexagon, Globe, Archive, PlayCircle } from 'lucide-react';
import { Concept, Chapter, FileContext } from '../types';
import { extractConcepts, generateConceptImage } from '../services/gemini';
import { Loader } from './ui/Loader';
import JSZip from 'jszip';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

const STYLES = [
  'Digital Art', 'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Sketch', 
  'Cyberpunk', 'Vaporwave', 'Neon', 'Line Art', 'Low Poly', 'Isometric',
  '3D Render', 'Pixel Art'
];
const RATIOS = ['1:1', '16:9', '4:3', '9:16', '3:4', '2:3'];

export const Visualizer: React.FC<Props> = ({ chapter, fileContext }) => {
  const [concepts, setConcepts] = useState<Concept[]>([]);
  const [images, setImages] = useState<Record<string, string>>({});
  const [loadingImages, setLoadingImages] = useState<Record<string, boolean>>({});
  const [isInitializing, setIsInitializing] = useState(false);

  const [selectedStyle, setSelectedStyle] = useState('Cyberpunk');
  const [selectedRatio, setSelectedRatio] = useState('1:1');
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => {
    let mounted = true;
    const loadConcepts = async () => {
      setIsInitializing(true);
      try {
        const extracted = await extractConcepts(fileContext, chapter);
        if (mounted) setConcepts(extracted);
      } catch (err) {
        console.error(err);
      } finally {
        if (mounted) setIsInitializing(false);
      }
    };

    loadConcepts();
    return () => { mounted = false; };
  }, [chapter, fileContext]);

  const handleGenerateImage = async (concept: Concept, forceRegenerate = false) => {
    if (loadingImages[concept.term] && !forceRegenerate) return;

    setLoadingImages(prev => ({ ...prev, [concept.term]: true }));
    try {
      const imgUrl = await generateConceptImage(concept.visualPrompt, selectedStyle, selectedRatio);
      setImages(prev => ({ ...prev, [concept.term]: imgUrl }));
    } catch (e) {
      console.error("Image gen failed", e);
    } finally {
      setLoadingImages(prev => ({ ...prev, [concept.term]: false }));
    }
  };

  const handleGenerateAll = () => {
      concepts.forEach((concept, index) => {
          if (!images[concept.term] && !loadingImages[concept.term]) {
              // Stagger calls slightly to avoid immediate rate limit hits on front end
              setTimeout(() => {
                  handleGenerateImage(concept);
              }, index * 1000);
          }
      });
  };

  const handleDownloadAll = async () => {
     if (Object.keys(images).length === 0) return;

     const zip = new JSZip();
     let count = 0;

     // Iterate over generated images
     Object.entries(images).forEach(([term, dataUrl]) => {
         const base64Data = (dataUrl as string).split(',')[1];
         zip.file(`lumina-concept-${term.replace(/\s+/g, '_')}.png`, base64Data, {base64: true});
         count++;
     });

     if (count === 0) return;

     const content = await zip.generateAsync({type: "blob"});
     const url = URL.createObjectURL(content);
     const a = document.createElement('a');
     a.href = url;
     a.download = `lumina-visual-pack-${chapter.id}.zip`;
     document.body.appendChild(a);
     a.click();
     setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
     }, 100);
  };

  if (isInitializing) {
    return <Loader text="Extracting neural concepts..." className="h-full" />;
  }

  const hasImages = Object.keys(images).length > 0;

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100">
       {/* Cyberpunk Toolbar */}
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 animate-fade-in shadow-[0_0_15px_rgba(0,243,255,0.05)] flex-wrap gap-2">
          <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono">
             <Hexagon size={18} className="text-[#00f3ff]" />
             <span>Visual_Matrix</span>
          </div>

          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <button onClick={() => setShowSettings(!showSettings)} className="p-1.5 text-zinc-500 hover:text-[#00f3ff] rounded">
                     <Settings2 size={16} />
                 </button>
                 {(showSettings || true) && (
                     <>
                        <select 
                            value={selectedStyle}
                            onChange={(e) => setSelectedStyle(e.target.value)}
                            className="bg-[#050505] text-xs text-[#00f3ff] border border-zinc-800 outline-none cursor-pointer font-mono uppercase w-28 rounded-sm"
                        >
                            {STYLES.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                        <div className="w-[1px] h-4 bg-zinc-700"></div>
                        <select 
                            value={selectedRatio}
                            onChange={(e) => setSelectedRatio(e.target.value)}
                            className="bg-[#050505] text-xs text-[#00f3ff] border border-zinc-800 outline-none cursor-pointer font-mono rounded-sm"
                        >
                             {RATIOS.map(r => <option key={r} value={r}>{r}</option>)}
                        </select>
                     </>
                 )}
              </div>

              <div className="flex items-center gap-2">
                <button 
                    onClick={handleGenerateAll}
                    disabled={concepts.every(c => images[c.term])}
                    className="flex items-center gap-2 px-3 py-1.5 bg-zinc-900 border border-zinc-700 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-sm text-xs font-bold font-mono uppercase transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    <PlayCircle size={14} />
                    Generate All
                </button>

                <button 
                  onClick={handleDownloadAll}
                  disabled={!hasImages}
                  className={`flex items-center gap-2 px-3 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-colors border ${
                      hasImages 
                      ? 'bg-zinc-900 border-[#00f3ff] text-[#00f3ff] shadow-[0_0_10px_rgba(0,243,255,0.2)] hover:bg-[#00f3ff] hover:text-black' 
                      : 'bg-zinc-900/50 border-zinc-800 text-zinc-600 cursor-not-allowed'
                  }`}
                >
                   <Archive size={14} />
                   Download All {hasImages ? `(${Object.keys(images).length})` : ''}
                </button>
              </div>
          </div>
       </div>

       <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar">
            <div className={`grid gap-6 ${selectedRatio.includes('9:16') || selectedRatio.includes('2:3') || selectedRatio.includes('3:4') ? 'grid-cols-2 md:grid-cols-3' : 'grid-cols-1 md:grid-cols-2'}`}>
                {concepts.map((concept, idx) => (
                <div key={idx} className="bg-[#0a0a0c] border border-zinc-800 rounded-lg overflow-hidden hover:border-cyan-500/50 transition-all group animate-fade-in-up flex flex-col shadow-lg" style={{ animationDelay: `${idx * 0.1}s` }}>
                    <div className="p-5 space-y-3 shrink-0 relative">
                        <div className="absolute top-0 left-0 w-1 h-full bg-[#ff003c]"></div>
                        <div className="flex items-start justify-between">
                            <h3 className="text-lg font-black text-white flex items-center gap-2 font-mono uppercase tracking-tight">
                            <Lightbulb size={16} className="text-[#ff003c]" />
                            {concept.term}
                            </h3>
                        </div>
                        <p className="text-sm text-zinc-400 leading-relaxed font-mono text-[12px]">
                            {concept.definition}
                        </p>
                    </div>

                    <div className={`relative bg-black border-t border-zinc-800 group/image flex-1 flex items-center justify-center aspect-[16/9] min-h-[200px]`}>
                    {images[concept.term] ? (
                        <>
                        <img 
                            src={images[concept.term]} 
                            alt={concept.term} 
                            className="w-full h-full object-contain animate-fade-in"
                        />
                        <div className="absolute inset-0 bg-black/70 opacity-0 group-hover/image:opacity-100 transition-all duration-300 flex items-center justify-center gap-3 backdrop-blur-sm">
                            <a
                            href={images[concept.term]}
                            download={`lumina-concept-${concept.term}.png`}
                            className="p-3 bg-zinc-900 text-cyan-400 rounded-sm hover:bg-cyan-500 hover:text-black transition-all border border-cyan-500/30"
                            title="Download"
                            >
                            <Download size={20} />
                            </a>
                            <button
                            onClick={() => handleGenerateImage(concept, true)}
                            className="p-3 bg-zinc-900 text-[#ff003c] rounded-sm hover:bg-[#ff003c] hover:text-white transition-all border border-[#ff003c]/30"
                            title="Regenerate"
                            >
                                <RefreshCw size={20} />
                            </button>
                        </div>
                        </>
                    ) : (
                        <div className="text-center p-6 w-full h-full flex items-center justify-center relative overflow-hidden">
                        {/* Grid Background */}
                        <div className="absolute inset-0 bg-[linear-gradient(to_right,#1f2937_1px,transparent_1px),linear-gradient(to_bottom,#1f2937_1px,transparent_1px)] bg-[size:16px_16px] opacity-10 pointer-events-none"></div>

                        {loadingImages[concept.term] ? (
                            <div className="flex flex-col items-center gap-2 text-zinc-500 animate-fade-in z-10">
                               <Loader text="Rendering..." />
                            </div>
                        ) : (
                            <button
                            onClick={() => handleGenerateImage(concept)}
                            className="flex flex-col items-center gap-3 text-zinc-600 hover:text-[#00f3ff] transition-colors group-hover:scale-105 transform duration-300 w-full h-full justify-center z-10"
                            >
                            <ImageIcon size={32} />
                            <span className="text-xs font-bold font-mono uppercase tracking-widest">Generate_Visual</span>
                            </button>
                        )}
                        </div>
                    )}
                    </div>

                    <div className="px-4 py-2 bg-black border-t border-zinc-900 flex items-center justify-between">
                        <p className="text-[10px] text-zinc-600 truncate max-w-[80%] font-mono">{concept.visualPrompt}</p>
                        {images[concept.term] && <div className="text-[10px] text-cyan-500 font-mono">RENDERED</div>}
                    </div>
                </div>
                ))}
            </div>
       </div>
    </div>
  );
};

export interface Chapter {
  id: number;
  title: string;
  pageStart?: number; // Optional, AI estimated
  pageEnd?: number;   // Optional, AI estimated
  description?: string;
}

export interface BookStructure {
  id: string; // Unique ID for the book in library
  title: string;
  author: string;
  chapters: Chapter[];
  bookmarks: number[]; // Array of chapter IDs
}

export interface Concept {
  term: string;
  definition: string;
  visualPrompt: string;
}

export interface DictionaryEntry {
  word: string;
  context: string;
  definition: string;
}

export interface PodcastState {
  audioUrl: string | null;
  isLoading: boolean;
  script: string | null;
}

export interface VisualState {
  concepts: Concept[];
  generatedImages: Record<string, string>; // term -> base64/url
  isLoading: boolean;
}

export interface DictionaryState {
  entries: DictionaryEntry[];
  isLoading: boolean;
}

export interface VideoState {
  videoUrl: string | null;
  isLoading: boolean;
  progressMessage: string;
}

export interface FileContext {
  content: string; // Base64 string for PDF, or raw text string for text files
  mimeType: string;
  isText: boolean; // Flag to determine how to send to Gemini
}

export interface NotebookItem {
  id: string;
  text: string;
  type: 'word' | 'sentence';
  definition?: string;
  timestamp: number;
  sourceChapter?: string;
  bookTitle?: string;
  bookAuthor?: string;
  comment?: string;
  contextSource?: string; // e.g. "Neural_Podcast", "Input_Stream", "Decoded_Layer"
}

export enum AppView {
  UPLOAD = 'UPLOAD',
  DASHBOARD = 'DASHBOARD'
}

export enum Tab {
  AUDIOBOOK = 'AUDIOBOOK',
  DICTIONARY = 'DICTIONARY',
  CONCEPTS = 'CONCEPTS',
  PODCAST = 'PODCAST',
  ANIMATION = 'ANIMATION',
  NOTEBOOK = 'NOTEBOOK'
}

export type ThemeColor = 'indigo' | 'emerald' | 'rose' | 'amber' | 'cyan';

export interface AppSettings {
  targetLanguage: string;
  highlightColor: ThemeColor;
  textSize: 'sm' | 'base' | 'lg' | 'xl';
  lineHeight: 'tight' | 'normal' | 'relaxed' | 'loose';
  letterSpacing: 'tighter' | 'normal' | 'wide' | 'wider';
  font: 'Inter' | 'Merriweather' | 'Playfair Display' | 'Roboto Mono' | 'Open Sans' | 'Orbitron' | 'Cinzel' | 'Source Code Pro' | 'Crimson Text';
}

export interface LibraryItem {
  book: BookStructure;
  fileContext: FileContext;
  uploadDate: number;
}

import React, { useState } from 'react';
import { Upload, BookOpen, Headphones, Image as ImageIcon, BookA, Film, Menu, X, ChevronRight, FileText, Mic2, Settings as SettingsIcon, Library as LibraryIcon, Tag, Bookmark, Cpu, Notebook as NotebookIcon, Terminal, Activity, Database, Shield } from 'lucide-react';
import JSZip from 'jszip';
import { BookStructure, Chapter, AppView, Tab, FileContext, AppSettings, LibraryItem, NotebookItem } from './types';
import { analyzeBookStructure } from './services/gemini';
import { PodcastPlayer } from './components/PodcastPlayer';
import { Visualizer } from './components/Visualizer';
import { VideoSummary } from './components/VideoSummary';
import { AudioBook } from './components/AudioBook';
import { Notebook } from './components/Notebook';
import { SettingsModal } from './components/SettingsModal';
import { GlobalContextLayer } from './components/GlobalContextLayer';
import { Loader } from './components/ui/Loader';
import { AIAssistant } from './components/AIAssistant';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.UPLOAD);

  const [library, setLibrary] = useState<LibraryItem[]>([]);
  const [activeBookId, setActiveBookId] = useState<string | null>(null);

  // Notebook State
  const [notebook, setNotebook] = useState<NotebookItem[]>([]);

  const activeBook = library.find(item => item.book.id === activeBookId)?.book || null;
  const activeFileContext = library.find(item => item.book.id === activeBookId)?.fileContext || null;

  const [activeChapterId, setActiveChapterId] = useState<number | null>(null);
  const activeChapter = activeBook?.chapters.find(c => c.id === activeChapterId) || null;

  const [activeTab, setActiveTab] = useState<Tab>(Tab.AUDIOBOOK);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showLibraryList, setShowLibraryList] = useState(false);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    targetLanguage: 'Spanish',
    highlightColor: 'indigo',
    textSize: 'base',
    lineHeight: 'normal',
    letterSpacing: 'normal',
    font: 'Inter'
  });

  const handleAddToNotebook = (item: Omit<NotebookItem, 'id' | 'timestamp'>) => {
      const newItem: NotebookItem = {
          ...item,
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          sourceChapter: activeChapter?.title,
          bookTitle: activeBook?.title,
          bookAuthor: activeBook?.author
      };
      setNotebook(prev => [newItem, ...prev]);
  };

  const handleDeleteNotebookItem = (id: string) => {
      setNotebook(prev => prev.filter(i => i.id !== id));
  };

  const handleBulkDeleteNotebookItems = (ids: string[]) => {
      setNotebook(prev => prev.filter(i => !ids.includes(i.id)));
  };

  const handleUpdateNotebookComment = (id: string, comment: string) => {
      setNotebook(prev => prev.map(item => item.id === id ? { ...item, comment } : item));
  };

  const processEpub = async (file: File): Promise<string> => {
    try {
      const zip = await JSZip.loadAsync(file);
      let fullText = "";
      const contentFiles = Object.keys(zip.files).filter(filename => 
        filename.match(/\.(html|xhtml|htm)$/i) && !filename.includes('__MACOSX')
      );
      contentFiles.sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
      const parser = new DOMParser();
      for (const filename of contentFiles) {
        const content = await zip.files[filename].async("string");
        const doc = parser.parseFromString(content, "text/html");
        fullText += (doc.body.textContent || "") + "\n\n";
      }
      if (!fullText) throw new Error("No readable text found in EPUB.");
      if (fullText.length > 100000) {
        return fullText.substring(0, 100000) + "... [Truncated]";
      }
      return fullText;
    } catch (e) {
      console.error("EPUB processing error", e);
      throw new Error("Could not parse EPUB file.");
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const allowedExtensions = ['.pdf', '.txt', '.md', '.html', '.xml', '.epub'];
    const hasAllowedExt = allowedExtensions.some(ext => file.name.toLowerCase().endsWith(ext));

    if (!hasAllowedExt) {
      setError("Supported formats: PDF, EPUB, TXT, MD, HTML.");
      return;
    }

    setIsProcessing(true);
    setError(null);

    const reader = new FileReader();
    const isEpub = file.name.toLowerCase().endsWith('.epub');
    const isTextBased = file.type.startsWith('text/') || 
                        ['.txt', '.md', '.html', '.xml'].some(ext => file.name.toLowerCase().endsWith(ext));

    const finalizeUpload = async (context: FileContext) => {
        try {
            const structure = await analyzeBookStructure(context);
            const newItem: LibraryItem = {
                book: structure,
                fileContext: context,
                uploadDate: Date.now()
            };
            setLibrary(prev => [newItem, ...prev]);
            setActiveBookId(structure.id);
            if (structure.chapters.length > 0) setActiveChapterId(structure.chapters[0].id);
            setView(AppView.DASHBOARD);
            setShowLibraryList(false);
        } catch (err: any) {
            setError("Analysis failed. " + err.message);
        } finally {
            setIsProcessing(false);
        }
    };

    if (isEpub) {
       try {
         const textContent = await processEpub(file);
         await finalizeUpload({
            content: textContent,
            mimeType: 'text/plain',
            isText: true
         });
       } catch (err: any) {
         setError(err.message || "Failed to process EPUB.");
         setIsProcessing(false);
       }
       return;
    }

    reader.onload = async (e) => {
      let context: FileContext;
      if (isTextBased) {
          let content = e.target?.result as string;
          if (content.length > 100000) content = content.substring(0, 100000) + "... [Truncated]";
          context = { content, mimeType: 'text/plain', isText: true };
      } else {
          const base64 = (e.target?.result as string).split(',')[1];
          context = { content: base64, mimeType: 'application/pdf', isText: false };
      }
      await finalizeUpload(context);
    };

    if (isTextBased) reader.readAsText(file);
    else reader.readAsDataURL(file);
  };

  const toggleBookmark = (chapterId: number) => {
    if (!activeBookId) return;
    setLibrary(prev => prev.map(item => {
        if (item.book.id === activeBookId) {
            const bookmarks = item.book.bookmarks || [];
            const isBookmarked = bookmarks.includes(chapterId);
            const newBookmarks = isBookmarked 
                ? bookmarks.filter(id => id !== chapterId)
                : [...bookmarks, chapterId];
            return { ...item, book: { ...item.book, bookmarks: newBookmarks } };
        }
        return item;
    }));
  };

  const renderContent = () => {
    // Notebook is global, doesn't need active chapter
    if (activeTab === Tab.NOTEBOOK) {
        return <Notebook 
          items={notebook} 
          onDelete={handleDeleteNotebookItem} 
          onBulkDelete={handleBulkDeleteNotebookItems}
          onUpdateComment={handleUpdateNotebookComment} 
          settings={settings} 
        />;
    }

    if (!activeChapter || !activeFileContext) return null;

    let content;
    switch (activeTab) {
      case Tab.AUDIOBOOK:
        content = <AudioBook chapter={activeChapter} fileContext={activeFileContext} settings={settings} onSettingsUpdate={setSettings} />;
        break;
      case Tab.PODCAST:
        content = <PodcastPlayer chapter={activeChapter} fileContext={activeFileContext} settings={settings} />;
        break;
      case Tab.CONCEPTS:
        content = <Visualizer chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      case Tab.ANIMATION:
        content = <VideoSummary chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      default:
        content = null;
    }

    return (
      <div key={`${activeBookId}-${activeChapter.id}-${activeTab}`} className="h-full animate-fade-in">
        {content}
      </div>
    );
  };

  if (view === AppView.UPLOAD) {
    return (
      <div className="min-h-screen bg-[#020202] bg-grid flex flex-col items-center justify-center p-6 relative overflow-hidden font-tech">

        {/* Decor: Corners */}
        <div className="absolute top-8 left-8 w-24 h-24 border-l border-t border-zinc-800 rounded-tl-lg pointer-events-none"></div>
        <div className="absolute bottom-8 right-8 w-24 h-24 border-r border-b border-zinc-800 rounded-br-lg pointer-events-none"></div>

        <div className="z-10 max-w-lg w-full text-center space-y-12">
          <div className="space-y-2 animate-fade-in-up">
             <div className="flex items-center justify-center gap-2 mb-4">
                <Terminal size={32} className="text-[#00f3ff]" />
             </div>
            <h1 className="text-7xl font-bold tracking-tighter text-white drop-shadow-[0_0_25px_rgba(0,243,255,0.3)]">
              Decod<span className="text-[#00f3ff]">Ebook</span>
            </h1>
            <p className="text-zinc-500 tracking-[0.2em] text-xs uppercase">
              V.4.2 // Neural Text Decoding Interface
            </p>
          </div>

          <div className="relative group animate-fade-in-up hud-border bg-[#050505] p-10 transition-all duration-500 hover:shadow-[0_0_30px_rgba(0,243,255,0.1)]" style={{ animationDelay: '0.1s' }}>

              {isProcessing ? (
                <Loader text="DECODING_SOURCE..." />
              ) : (
                <div className="relative flex flex-col items-center justify-center space-y-8">
                  <div className="relative">
                    <div className="w-32 h-32 bg-[#0a0a0c] border border-zinc-800 rounded-full flex items-center justify-center group-hover:border-[#00f3ff] transition-all duration-500">
                        <Upload className="w-12 h-12 text-zinc-600 group-hover:text-[#00f3ff] transition-colors" />
                    </div>
                    {/* Ring Animation */}
                    <div className="absolute -inset-2 border border-dashed border-zinc-800 rounded-full animate-spin-slow pointer-events-none group-hover:border-[#00f3ff]/30"></div>
                  </div>

                  <div className="space-y-2">
                    <p className="text-[#00f3ff] font-bold uppercase tracking-widest text-sm animate-pulse">Initialize Upload</p>
                    <p className="text-[10px] text-zinc-600 font-mono">SUPPORTED PROTOCOLS: PDF / EPUB / TXT / MD</p>
                  </div>

                  <input 
                    type="file" 
                    accept=".pdf,.txt,.md,.html,.xml,.epub"
                    onChange={handleFileUpload}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                </div>
              )}
          </div>

          {library.length > 0 && (
             <button 
                onClick={() => setView(AppView.DASHBOARD)}
                className="text-zinc-500 hover:text-[#00f3ff] text-xs font-mono uppercase tracking-widest transition-colors flex items-center gap-2 mx-auto border border-transparent hover:border-[#00f3ff]/30 px-4 py-2 rounded-sm"
             >
                <LibraryIcon size={14} />
                Access_Data_Bank [{library.length}]
             </button>
          )}
          {error && <p className="text-[#ff003c] text-xs font-mono border border-[#ff003c]/30 p-2 bg-[#ff003c]/5">{error}</p>}
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#020202] bg-grid text-zinc-300 overflow-hidden font-sans relative">
      <GlobalContextLayer onAddToNotebook={handleAddToNotebook} activeLanguage={settings.targetLanguage} />

      {/* Floating Chat Assistant - Now with smart ID tracking */}
      <AIAssistant 
        fileContext={activeFileContext} 
        bookTitle={activeBook?.title} 
        bookId={activeBook?.id} 
      />

      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        settings={settings}
        onUpdate={setSettings}
      />

      {/* Sidebar: Server Rack Style */}
      <aside 
        className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-[#050505] flex flex-col overflow-hidden relative z-20 transition-all duration-300 border-r border-zinc-900`}
      >
        <div className="p-4 border-b border-zinc-900 shrink-0 bg-black/80 backdrop-blur-sm relative overflow-hidden">
            {/* Header Glitch Bar */}
            <div className="absolute top-0 left-0 w-full h-[1px] bg-[#00f3ff] opacity-20"></div>

            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2">
                    <Cpu size={16} className="text-[#00f3ff]" />
                    <span className="text-xs font-tech font-bold text-white tracking-[0.2em]">DECOD.EBOOK</span>
                </div>
                <button 
                    onClick={() => setView(AppView.UPLOAD)} 
                    className="p-1.5 rounded-sm hover:bg-zinc-900 text-zinc-600 hover:text-[#00f3ff] transition-colors"
                    title="Upload New"
                >
                    <Upload size={14} />
                </button>
            </div>

            <div className="flex items-center justify-between mb-2">
                <button 
                onClick={() => setShowLibraryList(!showLibraryList)}
                className={`flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest transition-colors font-tech border px-2 py-1 rounded-sm w-full justify-between ${showLibraryList ? 'text-[#00f3ff] border-[#00f3ff]/50' : 'text-zinc-500 border-zinc-900 hover:border-zinc-700 hover:text-white'}`}
                >
                    <span className="flex items-center gap-2"><Database size={10} /> {showLibraryList ? "SESSION_DATA" : "DATA_BANKS"}</span>
                    <span className="text-[8px] animate-pulse">●</span>
                </button>
            </div>

            {!showLibraryList && activeBook && (
                <div className="mt-4 p-3 border border-zinc-800 bg-zinc-900/20 rounded-sm relative group cursor-default">
                    {/* Corner accent */}
                    <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-[#00f3ff]"></div>
                    <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-[#00f3ff]"></div>

                    <h1 className="font-bold text-xs text-white truncate leading-tight mb-1 font-tech uppercase tracking-wide">{activeBook.title}</h1>
                    <p className="text-[9px] text-zinc-500 truncate font-mono uppercase">{activeBook.author}</p>
                    <div className="mt-2 text-[9px] text-[#00f3ff] font-mono flex items-center gap-1">
                        <Activity size={10} /> SYS.ACTIVE
                    </div>
                </div>
            )}
        </div>

        <div className="flex-1 overflow-y-auto p-0 custom-scrollbar">
          {showLibraryList ? (
             <div className="flex flex-col">
                {library.map(item => (
                    <button
                        key={item.book.id}
                        onClick={() => {
                            setActiveBookId(item.book.id);
                            if(item.book.chapters.length > 0) setActiveChapterId(item.book.chapters[0].id);
                            setShowLibraryList(false);
                        }}
                        className={`w-full flex items-center gap-3 p-4 border-b border-zinc-900 transition-all group ${
                            activeBookId === item.book.id 
                            ? 'bg-[#00f3ff]/5' 
                            : 'hover:bg-zinc-900'
                        }`}
                    >
                        <div className={`w-1 h-8 ${activeBookId === item.book.id ? 'bg-[#00f3ff]' : 'bg-zinc-800'}`}></div>
                        <div className="text-left min-w-0">
                            <h4 className={`text-[10px] font-bold truncate font-tech uppercase tracking-wide ${activeBookId === item.book.id ? 'text-[#00f3ff]' : 'text-zinc-400'}`}>
                                {item.book.title}
                            </h4>
                            <p className="text-[9px] text-zinc-600 truncate font-mono">{item.book.chapters.length} DATA_BLOCKS</p>
                        </div>
                    </button>
                ))}
             </div>
          ) : (
             <div className="py-2">
                {activeBook?.chapters.map((chapter, idx) => {
                    const isBookmarked = activeBook.bookmarks?.includes(chapter.id);
                    return (
                        <div key={chapter.id} className="relative group flex items-center justify-between px-4 py-2 hover:bg-zinc-900/50">
                            <button
                                onClick={() => setActiveChapterId(chapter.id)}
                                className={`flex-1 text-left flex items-center gap-3 border-l-2 py-1 transition-all min-w-0 pr-2 ${
                                    activeChapterId === chapter.id 
                                    ? 'border-[#00f3ff]' 
                                    : 'border-transparent'
                                }`}
                            >
                                <span className={`text-[9px] font-mono w-6 text-right shrink-0 ${activeChapterId === chapter.id ? 'text-[#00f3ff]' : 'text-zinc-700'}`}>
                                    {String(idx + 1).padStart(2, '0')}
                                </span>
                                <div className="min-w-0 flex-1">
                                    <p className={`font-medium truncate font-tech uppercase tracking-tight text-xs ${activeChapterId === chapter.id ? 'text-white' : 'text-zinc-500'}`}>
                                        {chapter.title}
                                    </p>
                                </div>
                            </button>
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleBookmark(chapter.id); }}
                                className={`p-1.5 transition-colors shrink-0 ${isBookmarked ? 'text-amber-400' : 'text-zinc-800 hover:text-zinc-500'}`}
                                title={isBookmarked ? "Remove Bookmark" : "Add Bookmark"}
                            >
                                <Tag size={12} fill={isBookmarked ? "currentColor" : "none"} />
                            </button>
                        </div>
                    );
                })}
             </div>
          )}
        </div>

        <div className="p-0 border-t border-zinc-900 bg-black">
          <button 
            onClick={() => setIsSettingsOpen(true)}
            className="w-full flex items-center gap-3 p-4 hover:bg-zinc-900 text-zinc-500 hover:text-[#00f3ff] transition-colors text-[10px] font-bold font-tech uppercase tracking-widest"
          >
            <SettingsIcon size={14} />
            <span>SYS_CONFIG</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 relative bg-transparent z-10">

        {/* Header Status Bar */}
        <header className="h-14 border-b border-zinc-900 flex items-center justify-between px-4 bg-black/90 backdrop-blur-md sticky top-0 z-30 shrink-0">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="text-zinc-500 hover:text-[#00f3ff] transition-colors">
              {isSidebarOpen ? <X size={18} /> : <Menu size={18} />}
            </button>
            <div className="h-4 w-[1px] bg-zinc-800 mx-1"></div>

            {activeChapterId ? (
                <div className="flex items-center gap-2">
                    <span className="text-[9px] font-mono text-zinc-600 bg-zinc-900 border border-zinc-800 px-1.5 py-0.5">
                        SEC.{String(activeChapterId || 0).padStart(2, '0')}
                    </span>
                    <ChevronRight size={12} className="text-zinc-700" />
                    <span className="text-xs font-bold text-[#00f3ff] font-tech tracking-wide truncate max-w-[200px]">
                        {activeChapter?.title.toUpperCase()}
                    </span>
                </div>
            ) : (
                <span className="text-xs font-tech text-zinc-500 tracking-widest">AWAITING_INPUT</span>
            )}
          </div>

          {/* Module Selector */}
          <div className="flex items-center bg-zinc-950 border border-zinc-900 p-0.5 rounded-sm">
            {[
              { id: Tab.AUDIOBOOK, icon: Headphones, label: "SMART_READ" },
              { id: Tab.NOTEBOOK, icon: NotebookIcon, label: "NOTEBOOK" },
              { id: Tab.PODCAST, icon: Mic2, label: "PODCAST" },
              { id: Tab.CONCEPTS, icon: ImageIcon, label: "VISUALS" },
              { id: Tab.ANIMATION, icon: Film, label: "CINEMA" },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex items-center gap-2 px-3 py-1.5 transition-all text-[9px] font-bold uppercase tracking-wider font-tech ${
                  activeTab === tab.id 
                    ? 'bg-[#00f3ff]/10 text-[#00f3ff] shadow-[0_0_10px_rgba(0,243,255,0.1)]'
                    : 'text-zinc-600 hover:text-zinc-300 hover:bg-zinc-900'
                }`}
              >
                <tab.icon size={12} className={activeTab === tab.id ? 'text-[#00f3ff]' : ''} />
                <span className="hidden xl:inline">{tab.label}</span>
              </button>
            ))}
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 p-0 overflow-hidden relative">
          <div className="h-full w-full p-6 overflow-y-auto custom-scrollbar">
             {renderContent()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, RefreshCw, Loader as LoaderIcon, Hash } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 
  'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 
  'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  useEffect(() => {
    setSelectedLanguage(settings.targetLanguage);
  }, [settings.targetLanguage]);

  const writeString = (view: DataView, offset: number, string: string) => {
    for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
  };

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 24000 * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const cleanText = (text: string) => text.replace(/\*\*/g, '').trim();

  useEffect(() => {
    if (!script) { setSegments([]); return; }
    const lines = script.split('\n').filter(line => line.trim().length > 0);
    const totalChars = lines.reduce((acc, line) => acc + line.length, 0);
    let accumulatedChars = 0;
    const parsed: ScriptSegment[] = lines.map(line => {
      let speaker = 'Host';
      let text = line;
      if (line.includes(':')) {
        const parts = line.split(/:(.+)/);
        if (parts.length > 1) {
          speaker = cleanText(parts[0]);
          text = cleanText(parts[1]);
        }
      }
      const startPct = accumulatedChars / totalChars;
      accumulatedChars += line.length;
      const endPct = accumulatedChars / totalChars;
      return { speaker, text, startPct, endPct };
    });
    setSegments(parsed);
  }, [script]);

  const handleGenerate = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const hostConfig = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];
      const { audio, script } = await generatePodcastAudio(fileContext, chapter, selectedTone, hostConfig, selectedLanguage);
      const wavUrl = pcmToWavBlobUrl(audio);
      setAudioSrc(wavUrl);
      setScript(script);
      setActiveIndex(-1);
    } catch (e: any) {
      setError(e.message || "Failed to generate podcast. Please try again.");
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleRegenerate = () => {
    if (audioRef.current) audioRef.current.pause();
    setAudioSrc(null);
    setScript(null);
    setSegments([]);
    setActiveIndex(-1);
    setIsPlaying(false);
    handleGenerate();
  };

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `lumina-podcast-transcript-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const skipForward = () => { if (audioRef.current) audioRef.current.currentTime += 15; };
  const skipBackward = () => { if (audioRef.current) audioRef.current.currentTime -= 15; };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256; 
      analyser.smoothingTimeConstant = 0.85;
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;
    } catch (e) { console.warn("Audio Context init failed", e); }
  };

  const handleTimeUpdate = () => {
    if (!audioRef.current) return;
    const { currentTime, duration } = audioRef.current;
    if (!duration) return;
    const currentPct = currentTime / duration;
    const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
    if (index !== -1 && index !== activeIndex) {
      setActiveIndex(index);
      const el = segmentRefs.current[index];
      if (el) el.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  };

  // ELEGANT VISUALIZER LOOP
  useEffect(() => {
    if (!isPlaying || !canvasRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const draw = () => {
      const bufferLength = analyserRef.current ? analyserRef.current.frequencyBinCount : 64;
      const dataArray = new Uint8Array(bufferLength);
      if (analyserRef.current) analyserRef.current.getByteFrequencyData(dataArray);

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const width = canvas.width;
      const height = canvas.height;
      const barWidth = (width / bufferLength) * 2; 
      let x = 0;

      // Create Gradient
      const gradient = ctx.createLinearGradient(0, height, 0, 0);
      gradient.addColorStop(0, '#00f3ff00');
      gradient.addColorStop(0.5, '#00f3ff80');
      gradient.addColorStop(1, '#00f3ff');

      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.moveTo(0, height);

      // Draw elegant mirrored curve
      for (let i = 0; i < bufferLength; i++) {
        const value = analyserRef.current ? dataArray[i] : (isPlaying ? Math.random() * 100 : 0);
        const barHeight = (value / 255) * height * 0.8;

        // Smoother drawing using rects for now but with shadow for glow
        ctx.shadowBlur = 10;
        ctx.shadowColor = "#00f3ff";

        // Center alignment logic for elegance
        const centerX = width / 2;
        const offset = i * (width / 2 / bufferLength); // spacing

        // Right side
        ctx.fillRect(centerX + offset, (height - barHeight) / 2, barWidth/2, barHeight);
        // Left side mirrored
        ctx.fillRect(centerX - offset - (barWidth/2), (height - barHeight) / 2, barWidth/2, barHeight);
      }

      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying]);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 relative">
       {/* Toolbar */}
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-zinc-900 mb-4 flex items-center justify-between shrink-0 shadow-lg flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={16} className="text-[#00f3ff]" />
                 <span>NET_CAST_PROTOCOL</span>
              </div>
              <div className="hidden md:flex items-center gap-3 text-[10px] font-mono border-l border-zinc-800 pl-4">
                 <div className="flex items-center gap-1"><span className="text-zinc-600">H1:</span><span className="text-cyan-400 font-bold">{cleanText(hosts.host1).toUpperCase()}</span></div>
                 <div className="text-zinc-700">|</div>
                 <div className="flex items-center gap-1"><span className="text-zinc-600">H2:</span><span className="text-[#ff003c] font-bold">{cleanText(hosts.host2).toUpperCase()}</span></div>
              </div>
          </div>

          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-0.5 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={14} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-[#050505] text-[10px] text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-20 py-1">
                    {TONES.map(t => <option key={t} value={t}>{t}</option>)}
                 </select>
                 <div className="w-[1px] h-3 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={14} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-[#050505] text-[10px] text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-20 py-1">
                    {LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                 </select>
              </div>

              {!audioSrc && (
                  <button onClick={handleGenerate} disabled={isLoading} className="h-8 px-3 rounded-sm text-[10px] font-bold uppercase tracking-wider font-mono flex items-center gap-2 transition-all bg-[#00f3ff] text-black border border-[#00f3ff] hover:bg-[#00c2cc] shadow-[0_0_10px_rgba(0,243,255,0.3)] disabled:opacity-50">
                     {isLoading ? <LoaderIcon className="animate-spin" size={12} /> : <Play size={12} fill="currentColor" />}
                     {isLoading ? "INIT..." : "GENERATE"}
                  </button>
              )}
          </div>
       </div>

       {/* Main Player Area */}
       <div className="flex-1 flex flex-col gap-4 overflow-hidden relative">

           {/* Chapter Info Header */}
           <div className="bg-black/50 border-l-2 border-[#00f3ff] p-4 flex items-start gap-4 shrink-0">
               <div className="p-2 bg-[#00f3ff]/10 rounded text-[#00f3ff]">
                   <Hash size={20} />
               </div>
               <div>
                   <h2 className="text-lg font-bold text-white uppercase tracking-wide font-tech leading-none mb-1">
                       {chapter.title}
                   </h2>
                   <div className="flex items-center gap-2 text-[10px] font-mono text-zinc-500">
                       <span>CHAPTER_ID: {String(chapter.id).padStart(3, '0')}</span>
                       <span>//</span>
                       <span>DURATION_EST: 2-3 MIN</span>
                   </div>
               </div>
           </div>

           {/* Visualizer & Controls */}
           <div className="bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 min-h-[160px] flex flex-col shadow-2xl">
               <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative h-28">
                  {/* Grid */}
                  <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.03)_1px,transparent_1px)] bg-[size:32px_32px]"></div>
                  {audioSrc ? (
                      <canvas ref={canvasRef} width={600} height={120} className="w-full h-full opacity-80 mix-blend-screen"></canvas>
                  ) : (
                      <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs opacity-50">
                          {isLoading ? <Loader /> : <Activity size={24} />}
                          {!isLoading && <span>AWAITING_STREAM</span>}
                      </div>
                  )}
               </div>

               <div className="bg-[#020202] px-6 py-3 flex items-center justify-between border-t border-zinc-900">
                   <div className="flex-1 flex items-center gap-3">
                       <button onClick={handleRegenerate} disabled={!audioSrc || isLoading} className="p-2 text-zinc-600 hover:text-[#00f3ff] transition-colors hover:bg-zinc-900/50 rounded-full" title="Regenerate">
                         <RefreshCw size={16} className={isLoading ? "animate-spin" : ""} />
                       </button>
                   </div>

                   <div className="flex items-center gap-6 justify-center">
                       <button onClick={skipBackward} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 hover:bg-zinc-900 rounded-full transition-colors"><RotateCcw size={18} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full flex items-center justify-center border transition-all ${isPlaying ? 'border-[#00f3ff] text-[#00f3ff] shadow-[0_0_10px_rgba(0,243,255,0.4)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black hover:scale-105'}`}>
                         {isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-0.5" />}
                       </button>
                       <button onClick={skipForward} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 hover:bg-zinc-900 rounded-full transition-colors"><RotateCw size={18} /></button>
                   </div>

                   <div className="flex-1 flex justify-end">
                       <a href={audioSrc || '#'} download={`lumina-podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 rounded-full transition-colors ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30 cursor-not-allowed'}`} onClick={(e) => !audioSrc && e.preventDefault()}>
                         <Download size={18} />
                       </a>
                   </div>
               </div>
           </div>

           <audio ref={audioRef} src={audioSrc || undefined} onTimeUpdate={handleTimeUpdate} onEnded={() => setIsPlaying(false)} onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} crossOrigin="anonymous" className="hidden" />

           {/* Dialogue Stream */}
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-[#0a0a0c]/50 border border-zinc-800/50 rounded-lg overflow-hidden flex flex-col relative">
                  <div className="p-2 border-b border-zinc-800 bg-[#050505] flex items-center justify-between">
                      <div className="flex items-center gap-2 px-2 text-[10px] font-bold text-zinc-500 uppercase font-mono">
                        <Activity size={12} className="text-[#00f3ff]" /> Live_Transcript
                      </div>
                      <button onClick={downloadScript} className="text-zinc-500 hover:text-white p-1 hover:bg-zinc-800 rounded transition-colors"><FileDown size={14} /></button>
                  </div>
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-6 scroll-smooth custom-scrollbar bg-black/20">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const isHost1 = seg.speaker.includes(cleanText(hosts.host1));
                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${isHost1 ? 'justify-start' : 'justify-end'} animate-fade-in group`}>
                            <div className={`relative max-w-[80%] p-4 border transition-all duration-500 rounded-sm ${isActive 
                                   ? isHost1 
                                        ? 'bg-cyan-950/20 border-cyan-500/50 shadow-[0_0_20px_rgba(6,182,212,0.15)] text-white' 
                                        : 'bg-rose-950/20 border-[#ff003c]/50 shadow-[0_0_20px_rgba(255,0,60,0.15)] text-white'
                                   : 'bg-zinc-900/40 border-zinc-800 text-zinc-400'
                               }`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[8px] font-bold uppercase tracking-wider border flex items-center gap-1 z-10 ${isHost1 
                                        ? 'left-3 bg-[#050505] text-cyan-400 border-cyan-900' 
                                        : 'right-3 bg-[#050505] text-[#ff003c] border-rose-900 flex-row-reverse'
                                    }`}>
                                     <Radio size={8} /> {seg.speaker.toUpperCase()}
                                </div>
                                <p className="leading-relaxed text-xs font-mono">{seg.text}</p>
                            </div>
                        </div>
                      );
                    })}
                     <div className="h-8"></div>
                  </div>
               </div>
           ) : (
                <div className="flex-1 flex items-center justify-center text-zinc-700 font-mono text-xs border border-zinc-900 rounded-lg border-dashed">
                    AWAITING_NEURAL_TRANSCRIPT
                </div>
           )}
       </div>
