import React, { useState, useEffect } from 'react';
import { Lightbulb, Image as ImageIcon, Download, RefreshCw, Settings2, Hexagon, Globe, Archive, PlayCircle } from 'lucide-react';
import { Concept, Chapter, FileContext } from '../types';
import { extractConcepts, generateConceptImage } from '../services/gemini';
import { Loader } from './ui/Loader';
import JSZip from 'jszip';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

const STYLES = [
  'Digital Art', 'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Sketch', 
  'Cyberpunk', 'Vaporwave', 'Neon', 'Line Art', 'Low Poly', 'Isometric',
  '3D Render', 'Pixel Art'
];
const RATIOS = ['1:1', '16:9', '4:3', '9:16', '3:4', '2:3'];

export const Visualizer: React.FC<Props> = ({ chapter, fileContext }) => {
  const [concepts, setConcepts] = useState<Concept[]>([]);
  const [images, setImages] = useState<Record<string, string>>({});
  const [loadingImages, setLoadingImages] = useState<Record<string, boolean>>({});
  const [isInitializing, setIsInitializing] = useState(false);

  const [selectedStyle, setSelectedStyle] = useState('Cyberpunk');
  const [selectedRatio, setSelectedRatio] = useState('1:1');
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => {
    let mounted = true;
    const loadConcepts = async () => {
      setIsInitializing(true);
      try {
        const extracted = await extractConcepts(fileContext, chapter);
        if (mounted) setConcepts(extracted);
      } catch (err) {
        console.error(err);
      } finally {
        if (mounted) setIsInitializing(false);
      }
    };

    loadConcepts();
    return () => { mounted = false; };
  }, [chapter, fileContext]);

  const handleGenerateImage = async (concept: Concept, forceRegenerate = false) => {
    if (loadingImages[concept.term] && !forceRegenerate) return;

    setLoadingImages(prev => ({ ...prev, [concept.term]: true }));
    try {
      const imgUrl = await generateConceptImage(concept.visualPrompt, selectedStyle, selectedRatio);
      setImages(prev => ({ ...prev, [concept.term]: imgUrl }));
    } catch (e) {
      console.error("Image gen failed", e);
    } finally {
      setLoadingImages(prev => ({ ...prev, [concept.term]: false }));
    }
  };

  const handleGenerateAll = () => {
      concepts.forEach((concept, index) => {
          if (!images[concept.term] && !loadingImages[concept.term]) {
              setTimeout(() => {
                  handleGenerateImage(concept);
              }, index * 1000);
          }
      });
  };

  const handleDownloadAll = async () => {
     if (Object.keys(images).length === 0) return;
     const zip = new JSZip();
     let count = 0;
     Object.entries(images).forEach(([term, dataUrl]) => {
         const base64Data = (dataUrl as string).split(',')[1];
         zip.file(`lumina-concept-${term.replace(/\s+/g, '_')}.png`, base64Data, {base64: true});
         count++;
     });
     if (count === 0) return;
     const content = await zip.generateAsync({type: "blob"});
     const url = URL.createObjectURL(content);
     const a = document.createElement('a');
     a.href = url;
     a.download = `lumina-visual-pack-${chapter.id}.zip`;
     document.body.appendChild(a);
     a.click();
     setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
  };

  if (isInitializing) {
    return <Loader text="Extracting neural concepts..." className="h-full" />;
  }

  const hasImages = Object.keys(images).length > 0;

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100">
       {/* Unified Toolbar */}
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-zinc-900 mb-4 flex items-center justify-between shrink-0 shadow-lg flex-wrap gap-2">
          <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
             <Hexagon size={16} className="text-[#00f3ff]" />
             <span>VISUAL_MATRIX</span>
          </div>

          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-0.5 rounded-sm border border-zinc-800">
                 <button onClick={() => setShowSettings(!showSettings)} className="p-1.5 text-zinc-500 hover:text-[#00f3ff] rounded"><Settings2 size={14} /></button>
                 {(showSettings || true) && (
                     <>
                        <select value={selectedStyle} onChange={(e) => setSelectedStyle(e.target.value)} className="bg-[#050505] text-[10px] text-[#00f3ff] border-none outline-none cursor-pointer font-mono uppercase w-28 py-1">
                            {STYLES.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                        <div className="w-[1px] h-3 bg-zinc-700"></div>
                        <select value={selectedRatio} onChange={(e) => setSelectedRatio(e.target.value)} className="bg-[#050505] text-[10px] text-[#00f3ff] border-none outline-none cursor-pointer font-mono py-1">
                             {RATIOS.map(r => <option key={r} value={r}>{r}</option>)}
                        </select>
                     </>
                 )}
              </div>

              <div className="flex items-center gap-2">
                <button onClick={handleGenerateAll} disabled={concepts.every(c => images[c.term])} className="h-8 px-3 rounded-sm text-[10px] font-bold uppercase tracking-wider font-mono flex items-center gap-2 transition-all bg-zinc-900 border border-zinc-700 hover:border-[#00f3ff] hover:text-[#00f3ff] text-zinc-400 disabled:opacity-50">
                    <PlayCircle size={12} /> GENERATE ALL
                </button>
                <button onClick={handleDownloadAll} disabled={!hasImages} className={`h-8 px-3 rounded-sm text-[10px] font-bold uppercase tracking-wider font-mono flex items-center gap-2 transition-all border ${hasImages ? 'bg-zinc-900 border-[#00f3ff] text-[#00f3ff] hover:bg-[#00f3ff] hover:text-black' : 'bg-zinc-900/50 border-zinc-800 text-zinc-600 cursor-not-allowed'}`}>
                   <Archive size={12} /> SAVE PACK
                </button>
              </div>
          </div>
       </div>

       <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar">
            <div className={`grid gap-6 ${selectedRatio.includes('9:16') || selectedRatio.includes('2:3') || selectedRatio.includes('3:4') ? 'grid-cols-2 md:grid-cols-3' : 'grid-cols-1 md:grid-cols-2'}`}>
                {concepts.map((concept, idx) => (
                <div key={idx} className="bg-[#0a0a0c] border border-zinc-800 rounded-lg overflow-hidden hover:border-cyan-500/50 transition-all group animate-fade-in-up flex flex-col shadow-lg" style={{ animationDelay: `${idx * 0.1}s` }}>
