                                <Download size={18} />
                            </a>
                            <button onClick={() => handleGenerateImage(concept, true)} className="p-2 bg-zinc-900 text-[#ff003c] rounded-sm hover:bg-[#ff003c] hover:text-white transition-all border border-[#ff003c]/30">
                                <RefreshCw size={18} />
                            </button>
                        </div>
                        </>
                    ) : (
                        <div className="text-center p-6 w-full h-full flex items-center justify-center relative overflow-hidden">
                        <div className="absolute inset-0 bg-[linear-gradient(to_right,#1f2937_1px,transparent_1px),linear-gradient(to_bottom,#1f2937_1px,transparent_1px)] bg-[size:16px_16px] opacity-10 pointer-events-none"></div>
                        {loadingImages[concept.term] ? (
                            <div className="flex flex-col items-center gap-2 text-zinc-500 animate-fade-in z-10"><Loader text="Rendering..." /></div>
                        ) : (
                            <button onClick={() => handleGenerateImage(concept)} className="flex flex-col items-center gap-3 text-zinc-600 hover:text-[#00f3ff] transition-colors group-hover:scale-105 transform duration-300 w-full h-full justify-center z-10">
                                <ImageIcon size={24} />
                                <span className="text-[10px] font-bold font-mono uppercase tracking-widest">Generate_Visual</span>
                            </button>
