import { GoogleGenAI, Type, Modality, Chat, Content } from "@google/genai";
import { BookStructure, Chapter, Concept, DictionaryEntry, FileContext } from "../types";

// Helper to get AI instance. Re-instantiate to capture updated API keys if needed (e.g. for Veo)
const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Clean text utility
export const cleanGenAiText = (text: string): string => {
  if (!text) return "";
  // Remove markdown bold/italic markers
  return text
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`/g, '')
    .replace(/^#+\s/gm, '') // Remove headers like # 
    .trim();
};

// Retry helper for robust network requests
const withRetry = async <T>(fn: () => Promise<T>, retries = 5, delay = 3000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    // 1. Safe Error Details Extraction
    // Handle the specific structure: {"error":{"code":429,"message":"...","status":"RESOURCE_EXHAUSTED"}}
    const getErrorDetails = (e: any) => {
        if (e.error && typeof e.error === 'object') return e.error;
        if (e.response?.data?.error) return e.response.data.error;
        return e;
    };

    const details = getErrorDetails(error);
    const code = details.code || details.status || error.status || error.code;
    const message = String(details.message || error.message || JSON.stringify(error)).toLowerCase();
    const status = String(details.status || "").toLowerCase();

    // 2. Categorize Error
    const isNetworkError = message.includes('xhr') || 
                           message.includes('fetch') || 
                           message.includes('network') || 
                           message.includes('failed to fetch');

    const numericCode = Number(code);
    const isServerError = (numericCode >= 500 && numericCode < 600);

    // Rate limit detection
    const isRateLimit = numericCode === 429 || 
                        message.includes('429') || 
                        message.includes('quota') || 
                        message.includes('resource_exhausted') ||
                        status.includes('resource_exhausted');

    // 3. Retry Logic
    if (retries > 0 && (isNetworkError || isServerError || isRateLimit)) {
      // Aggressive backoff for rate limits
      let nextDelay = delay;
      if (isRateLimit) {
          // If quota exceeded, start with at least 15s and increase significantly
          nextDelay = Math.max(delay, 15000) * 1.5; 
      } else {
          nextDelay = delay * 2;
      }

      // Cap max delay at 3 minutes
      nextDelay = Math.min(nextDelay, 180000);
      // Add Jitter
      nextDelay += Math.random() * 2000; 

      console.warn(`Gemini API request failed (${code}: ${status}). Retrying in ${Math.round(nextDelay/1000)}s... (${retries} attempts left)`);

      await new Promise(resolve => setTimeout(resolve, nextDelay));
      return withRetry(fn, retries - 1, nextDelay);
    }

    // If retries exhausted, ensure we throw a useful Error object if it was a raw JSON object
    if (typeof error === 'object' && !error.message && details.message) {
        throw new Error(details.message);
    }

    throw error;
  }
};

// Helper to construct the content part based on file type
const getFilePart = (file: FileContext) => {
  if (file.isText) {
    return {
      text: file.content
    };
  } else {
    return {
      inlineData: {
        mimeType: file.mimeType,
        data: file.content
      }
    };
  }
};

export const analyzeBookStructure = async (file: FileContext): Promise<BookStructure> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          getFilePart(file),
          {
            text: "Analyze this book content. Extract the book title, author, and a list of chapters. For each chapter, provide a title and a one-sentence description. If the content is short, divide it into logical sections. CRITICAL: Provide a UNIQUE list of chapters. Do NOT list the same chapter twice. Ensure the IDs are sequential integers starting from 1. Return all titles and descriptions in the SAME LANGUAGE as the book content. Return strictly JSON."
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    if (!response.text) throw new Error("Failed to analyze book structure");
    const data = JSON.parse(response.text);
    return {
        ...data,
        id: crypto.randomUUID(), // Client-side ID for library
        bookmarks: [] // Init bookmarks
    } as BookStructure;
  }, 5, 8000); // Increased retries and initial delay
};

interface HostConfig {
  host1: string;
  voice1: string;
  host2: string;
  voice2: string;
}

export const generatePodcastAudio = async (
  file: FileContext,
  chapter: Chapter,
  tone: string = 'Engaging',
  hosts: HostConfig,
  language: string = 'English'
): Promise<{ audio: string; script: string }> => {
  return withRetry(async () => {
    const ai = getAi();

    // 1. Generate Script
    const scriptResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Create a ${tone} podcast script discussing "${chapter.title}" of this book. The conversation is between two hosts: ${hosts.host1} and ${hosts.host2}. 

          Host Personalities:
          - ${hosts.host1}: Main host, leads the conversation.
          - ${hosts.host2}: Co-host, provides insights or counter-arguments.

          IMPORTANT: The script must be written in ${language}. Translate the content concepts if necessary to match this target language.

          Keep it under 2 minutes spoken length. Focus on the key insights. Format clearly for TTS with "Speaker: Text" format. Tone guide: ${tone}.` }
        ]
      }
    });

    const script = scriptResponse.text;
    if (!script) throw new Error("Failed to generate script");

    // 2. Generate Audio
    const audioResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{
        parts: [{ text: script }]
      }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              {
                speaker: hosts.host1,
                voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice1 } }
              },
              {
                speaker: hosts.host2,
                voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice2 } }
              }
            ]
          }
        }
      }
    });

    const base64Audio = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) {
      console.error("Audio generation missing inlineData", audioResponse);
      throw new Error("Failed to generate audio content");
    }

    return { audio: base64Audio, script };
  }, 6, 8000); // Increased retries for heavy podcast generation
};

