export const generateSpeech = async (
  text: string,
  voiceName: string
): Promise<string> => {
  // Guard against empty input which causes API errors
  if (!text || text.trim().length === 0) return "";

  try {
    return await withRetry(async () => {
        const ai = getAi();

        const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{
            parts: [{ text: text }]
        }],
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
            voiceConfig: {
                prebuiltVoiceConfig: { voiceName: voiceName }
            }
            }
        }
        });

        const candidate = response.candidates?.[0];
        const base64Audio = candidate?.content?.parts?.[0]?.inlineData?.data;

        if (!base64Audio) {
            // Treat no data as a soft failure (return empty string) so we don't block
            console.warn("TTS returned no data for text chunk.");
            return ""; 
        }
        return base64Audio;
    }, 5, 5000); // 5 retries, 5s initial delay
  } catch (e: any) {
    // Enhanced detection for the specific JSON error structure provided by user
    const details = e.error || e;
    const code = e.status || e.code || details.code;
    const msg = (details.message || e.message || JSON.stringify(e)).toLowerCase();

    const isRateLimit = 
        code === 429 || 
        msg.includes('429') || 
        msg.includes('quota') || 
        msg.includes('resource_exhausted');

    if (isRateLimit) {
        // Log a warning to console instead of Error, to reduce noise for handled conditions
        console.warn(`TTS Rate Limit hit (Quota). Bubbling up to queue processor.`);
        throw e; // CRITICAL: Rethrow so the queue processor pauses
    }

    // Only log actual unexpected errors
    console.error("Generate Speech Failed (Non-retriable):", e);
    return "";
  }
};

// VEO VIDEO GENERATION
export const generateSummaryVideo = async (
  file: FileContext,
  chapter: Chapter,
  onProgress: (status: string) => void,
  style: string = 'Cinematic',
  language: string = 'English'
): Promise<string> => {
  const ai = getAi();

  // 1. First, get a summary text to base the video on
  onProgress("Analyzing chapter for visual summary...");
  const summaryResponse = await withRetry(async () => ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: {
      parts: [
        getFilePart(file),
        { text: `Create a very short, vivid visual description (prompt) for a video that summarizes the core value/theme of "${chapter.title}". The prompt should describe a scene, movement, and style (${style}). 

        IMPORTANT: The response must be a visual prompt in English. 
        Context Language: ${language}.

        Keep it under 50 words.` }
      ]
    }
  }), 3, 3000);
  const videoPrompt = summaryResponse.text || `Abstract representation of ${chapter.title}`;

  onProgress(`Generating video: "${videoPrompt.substring(0, 30)}..."`);

  // 2. Generate Video
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: videoPrompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  // Polling loop
  while (!operation.done) {
    onProgress("Rendering video... (this may take a minute)");
    await new Promise(resolve => setTimeout(resolve, 10000)); // Increased wait time to 10s
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  // Check for operation-level errors (e.g., safety filters, internal errors)
  if (operation.error) {
     console.error("Veo Operation Error:", operation.error);
     throw new Error(`Video generation failed: ${operation.error.message || "Unknown error"}`);
  }

  const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!videoUri) {
      console.error("Veo Operation Response Missing URI:", operation);
      throw new Error("No video returned from Veo (URI missing).");
  }

  // 3. Fetch the actual video bytes using the API key
  onProgress("Downloading video...");
  const videoUrlWithKey = `${videoUri}&key=${process.env.API_KEY}`;

  const res = await fetch(videoUrlWithKey);
  const blob = await res.blob();
  return URL.createObjectURL(blob);
};

