const formatTime = (seconds: number): string => {
  if (!seconds || isNaN(seconds)) return "00:00";
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
};

const rearrangeAndCleanText = (text: string): string => {
  if (!text) return "";
  let cleaned = text;
  cleaned = cleaned.replace(/(\w)-\n(\w)/g, '$1$2');
  const paragraphs = cleaned.split(/\n\s*\n/);
  const processedParagraphs = paragraphs.map(p => p.replace(/\n/g, ' ').trim());
  return processedParagraphs.join('\n\n');
};

const paginateText = (text: string, targetSize: number): string[] => {
  const pages: string[] = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= targetSize) {
      pages.push(remaining.trim());
      break;
    }
    let splitIdx = targetSize;
    const paragraphBreak = remaining.lastIndexOf('\n\n', targetSize);
    if (paragraphBreak > targetSize * 0.7) splitIdx = paragraphBreak;
    else {
      const sentenceBreak = Math.max(
          remaining.lastIndexOf('. ', targetSize),
          remaining.lastIndexOf('? ', targetSize),
          remaining.lastIndexOf('! ', targetSize)
      );
      if (sentenceBreak > targetSize * 0.5) splitIdx = sentenceBreak + 1;
      else {
          const spaceBreak = remaining.lastIndexOf(' ', targetSize);
          if (spaceBreak > 0) splitIdx = spaceBreak;
      }
    }
    pages.push(remaining.substring(0, splitIdx).trim());
    remaining = remaining.substring(splitIdx).trim();
  }
  return pages;
};

const splitIntoSentences = (text: string, isChinese: boolean = false): string[] => {
  if (!text) return [];
  if (isChinese) return text.match(/[^。！？]+[。！？]+|[^。！？]+$/g) || [text];
  return text.match(/[^.!?]+[.!?]+(\s+|$)|[^.!?]+$/g) || [text];
};

const escapeRegExp = (string: string) => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const processQueue = async <T, R>(
  items: T[],
  concurrency: number,
  fn: (item: T, index: number) => Promise<R>,
  checkAbort?: () => boolean
): Promise<(R | null)[]> => {
  const results: (R | null)[] = new Array(items.length).fill(null);
  const queue = items.map((item, index) => ({ item, index }));
  const worker = async () => {
    while (queue.length > 0) {
      if (checkAbort && checkAbort()) break;
      const task = queue.shift();
      if (!task) break; 
      const { item, index } = task;
      try {
        const result = await fn(item, index);
        results[index] = result;
        await new Promise(resolve => setTimeout(resolve, 300)); 
      } catch (e: any) {
        console.warn(`Task ${index} failed`, e);
        results[index] = null;
      }
    }
  };
  const workers = Array.from({ length: concurrency }).map(() => worker());
  await Promise.all(workers);
  return results;
};

export const AudioBook: React.FC<Props> = ({ chapter, fileContext, settings, onSettingsUpdate }) => {
  const [pages, setPages] = useState<string[]>([]);
  const [paragraphData, setParagraphData] = useState<ParagraphData[]>([]);
  const [flatSentenceMap, setFlatSentenceMap] = useState<SentenceMap[]>([]);
  const [currentPage, setCurrentPage] = useState(0);
  const [isLoadingText, setIsLoadingText] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [viewMode, setViewMode] = useState<'single' | 'split'>('single');
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [timings, setTimings] = useState<ChunkTiming[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generationProgress, setGenerationProgress] = useState("");
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [selectedVoice, setSelectedVoice] = useState('Puck');
  const [autoScroll, setAutoScroll] = useState(true);
  const [autoFlip, setAutoFlip] = useState(false);
  const [activeSentenceIndex, setActiveSentenceIndex] = useState<number>(-1);
  const [searchQuery, setSearchQuery] = useState("");
  const [searchMatches, setSearchMatches] = useState<GlobalMatch[]>([]);
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [bookSentences, setBookSentences] = useState<string[][]>([]);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const abortGenerationRef = useRef<boolean>(false);
  const isProgrammaticScroll = useRef(false);
  const activeMatchRef = useRef<HTMLSpanElement | null>(null);
  const nextAutoGenerateRef = useRef<boolean>(false);

  const resetAudioState = () => {
    setAudioSrc(null);
    setTimings([]);
    setIsPlaying(false);
    setPlaybackProgress(0);
    setCurrentTime(0);
    setDuration(0);
    setActiveSentenceIndex(-1);
    setGenerationProgress("");
  };

  const loadContent = async () => {
    setIsLoadingText(true);
    setError(null);
    resetAudioState();
    try {
      const rawText = await extractChapterText(fileContext, chapter);
      const cleanText = rearrangeAndCleanText(rawText);
      const paginated = paginateText(cleanText, PAGE_TARGET_SIZE);
      setPages(paginated);
    } catch (err: any) {
      setError(err.message || "Failed to extract text.");
    } finally {
      setIsLoadingText(false);
    }
  };

  useEffect(() => { loadContent(); }, [chapter, fileContext]);

  useEffect(() => {
    if (pages.length === 0) return;
    setBookSentences(pages.map(pageText => {
      return pageText.split(/\n\s*\n/).filter(p => p.trim().length > 0).flatMap(pText => 
        splitIntoSentences(pText).map(s => s.trim()).filter(s => s.length > 0)
      );
    }));
  }, [pages]);

  useEffect(() => {
     if (!pages[currentPage]) return;
     const pageText = pages[currentPage];
     const rawParagraphs = pageText.split(/\n\s*\n/).filter(p => p.trim().length > 0);
     const newParagraphData: ParagraphData[] = [];
     const newSentenceMap: SentenceMap[] = [];
     let globalIdx = 0;
     rawParagraphs.forEach((pText, pIndex) => {
         const sentences = splitIntoSentences(pText).map(s => s.trim()).filter(s => s.length > 0);
         sentences.forEach((s, sIndex) => {
             newSentenceMap.push({ pIndex, sIndex, globalIndex: globalIdx, text: s });
             globalIdx++;
         });
         newParagraphData.push({ original: sentences, translated: [] });
     });
     setParagraphData(newParagraphData);
     setFlatSentenceMap(newSentenceMap);
     resetAudioState();
     abortGenerationRef.current = true;
     if (nextAutoGenerateRef.current) {
         nextAutoGenerateRef.current = false;
         generatePageAudio();
     }
  }, [currentPage, pages]);

  useEffect(() => {
    const loadTranslation = async () => {
      if (viewMode === 'split' && pages[currentPage]) {
        setIsTranslating(true);
        try {
          const translatedText = await translateText(pages[currentPage], settings.targetLanguage);
          const rawTransParagraphs = rearrangeAndCleanText(translatedText).split(/\n\s*\n/).filter(p => p.trim().length > 0);
          const isChineseTarget = settings.targetLanguage.includes("Chinese");
          setParagraphData(prev => prev.map((p, idx) => ({ 
            ...p, translated: splitIntoSentences(rawTransParagraphs[idx] || "", isChineseTarget) 
          })));
        } catch(e) { console.error(e); } finally { setIsTranslating(false); }
      }
    };
    loadTranslation();
  }, [currentPage, viewMode, settings.targetLanguage, pages]);

  useEffect(() => {
    if (audioRef.current) audioRef.current.playbackRate = playbackRate;
  }, [playbackRate]);

  useEffect(() => {
    let animationFrameId: number;
    const syncPlayback = () => {
        if (!audioRef.current) return;
        const t = audioRef.current.currentTime;
        const d = audioRef.current.duration;
        setCurrentTime(t);
        setDuration(d || 0);
        setPlaybackProgress((t / (d || 1)) * 100);
        const activeIdx = timings.findIndex(chunk => !chunk.isWhitespace && t >= chunk.start && t < chunk.end);
        if (activeIdx !== -1 && activeIdx !== activeSentenceIndex) setActiveSentenceIndex(activeIdx);
        if (isPlaying) animationFrameId = requestAnimationFrame(syncPlayback);
    };
    if (isPlaying) animationFrameId = requestAnimationFrame(syncPlayback);
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, timings, activeSentenceIndex]);

  const generatePageAudio = async () => {
    if (isGenerating || !flatSentenceMap.length) return;
    abortGenerationRef.current = false;
    setIsGenerating(true);
    setGenerationProgress("INIT_CORE...");
    try {
      const sentences = flatSentenceMap.map(m => m.text);
      const audioResults = await processQueue<string, string | null>(
        sentences, CONCURRENCY_LIMIT, 
        async (sentence, idx) => {
           if (abortGenerationRef.current) return null;
           setGenerationProgress(`PACKET_${idx + 1}_OF_${sentences.length}`);
           return await generateSpeech(sentence, selectedVoice);
        },
        () => abortGenerationRef.current
      );
      if (abortGenerationRef.current) return;
      const audioBuffers: Uint8Array[] = [];
      const newTimings: ChunkTiming[] = [];
      let currentOffset = 0;
      const BYTES_PER_SEC = 48000; 
      for (let i = 0; i < sentences.length; i++) {
        const b64 = audioResults[i];
        if (!b64) {
          newTimings.push({ text: sentences[i], start: currentOffset / BYTES_PER_SEC, end: currentOffset / BYTES_PER_SEC, isWhitespace: true });
          continue;
        }
        const binaryString = atob(b64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let k = 0; k < len; k++) bytes[k] = binaryString.charCodeAt(k);
        audioBuffers.push(bytes);
        const startSec = currentOffset / BYTES_PER_SEC;
        const durationSec = len / BYTES_PER_SEC;
        newTimings.push({ text: sentences[i], start: startSec, end: startSec + durationSec, isWhitespace: false });
        currentOffset += len;
      }
      const mergedBuffer = new Uint8Array(currentOffset);
      let offset = 0;
      for (const buf of audioBuffers) { mergedBuffer.set(buf, offset); offset += buf.length; }
      const wavHeader = new ArrayBuffer(44);
      const view = new DataView(wavHeader);
      const writeStr = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
      writeStr(view, 0, 'RIFF'); view.setUint32(4, 36 + currentOffset, true); writeStr(view, 8, 'WAVE');
      writeStr(view, 12, 'fmt '); view.setUint32(16, 16, true); view.setUint16(20, 1, true); view.setUint16(22, 1, true);
      view.setUint32(24, 24000, true); view.setUint32(28, 48000, true); view.setUint16(32, 2, true); view.setUint16(34, 16, true);
      writeStr(view, 36, 'data'); view.setUint32(40, currentOffset, true);
      const blob = new Blob([wavHeader, mergedBuffer], { type: 'audio/wav' });
      setTimings(newTimings); 
      setAudioSrc(URL.createObjectURL(blob));
      setIsPlaying(true);
    } catch (e: any) {
      setGenerationProgress("ERR: " + e.message);
    } finally {
      setIsGenerating(false);
    }
