const formatTime = (seconds: number): string => {
  if (!seconds || isNaN(seconds)) return "00:00";
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
};

const rearrangeAndCleanText = (text: string): string => {
  if (!text) return "";
  let cleaned = text;
  cleaned = cleaned.replace(/(\w)-\n(\w)/g, '$1$2');
  const paragraphs = cleaned.split(/\n\s*\n/);
  const processedParagraphs = paragraphs.map(p => p.replace(/\n/g, ' ').trim());
  return processedParagraphs.join('\n\n');
};

const paginateText = (text: string, targetSize: number): string[] => {
  const pages: string[] = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= targetSize) {
      pages.push(remaining.trim());
      break;
    }
    let splitIdx = targetSize;
    const paragraphBreak = remaining.lastIndexOf('\n\n', targetSize);
    if (paragraphBreak > targetSize * 0.7) splitIdx = paragraphBreak;
    else {
      const sentenceBreak = Math.max(
          remaining.lastIndexOf('. ', targetSize),
          remaining.lastIndexOf('? ', targetSize),
          remaining.lastIndexOf('! ', targetSize)
      );
      if (sentenceBreak > targetSize * 0.5) splitIdx = sentenceBreak + 1;
      else {
          const spaceBreak = remaining.lastIndexOf(' ', targetSize);
          if (spaceBreak > 0) splitIdx = spaceBreak;
      }
    }
    pages.push(remaining.substring(0, splitIdx).trim());
    remaining = remaining.substring(splitIdx).trim();
  }
  return pages;
};

const splitIntoSentences = (text: string, isChinese: boolean = false): string[] => {
  if (!text) return [];
  if (isChinese) return text.match(/[^。！？]+[。！？]+|[^。！？]+$/g) || [text];
  return text.match(/[^.!?]+[.!?]+(\s+|$)|[^.!?]+$/g) || [text];
};

const escapeRegExp = (string: string) => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const processQueue = async <T, R>(
  items: T[],
  concurrency: number,
  fn: (item: T, index: number) => Promise<R>,
  checkAbort?: () => boolean
): Promise<(R | null)[]> => {
  const results: (R | null)[] = new Array(items.length).fill(null);
  const queue = items.map((item, index) => ({ item, index }));
  const worker = async () => {
    while (queue.length > 0) {
      if (checkAbort && checkAbort()) break;
      const task = queue.shift();
      if (!task) break; 
      const { item, index } = task;
      try {
        const result = await fn(item, index);
        results[index] = result;
        await new Promise(resolve => setTimeout(resolve, 300)); 
      } catch (e: any) {
        console.warn(`Task ${index} failed`, e);
        results[index] = null;
      }
    }
  };
  const workers = Array.from({ length: concurrency }).map(() => worker());
  await Promise.all(workers);
  return results;
};

export const AudioBook: React.FC<Props> = ({ chapter, fileContext, settings, onSettingsUpdate }) => {
  const [pages, setPages] = useState<string[]>([]);
  const [paragraphData, setParagraphData] = useState<ParagraphData[]>([]);
  const [flatSentenceMap, setFlatSentenceMap] = useState<SentenceMap[]>([]);
  const [currentPage, setCurrentPage] = useState(0);
  const [isLoadingText, setIsLoadingText] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [viewMode, setViewMode] = useState<'single' | 'split'>('single');
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [timings, setTimings] = useState<ChunkTiming[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generationProgress, setGenerationProgress] = useState("");
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [selectedVoice, setSelectedVoice] = useState('Puck');
  const [autoScroll, setAutoScroll] = useState(true);
  const [autoFlip, setAutoFlip] = useState(false);
  const [activeSentenceIndex, setActiveSentenceIndex] = useState<number>(-1);
  const [searchQuery, setSearchQuery] = useState("");

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const abortGenerationRef = useRef<boolean>(false);
  const isProgrammaticScroll = useRef(false);
  const nextAutoGenerateRef = useRef<boolean>(false);

  const resetAudioState = () => {
    setAudioSrc(null);
    setTimings([]);
    setIsPlaying(false);
    setPlaybackProgress(0);
    setCurrentTime(0);
    setDuration(0);
    setActiveSentenceIndex(-1);
    setGenerationProgress("");
  };

  const loadContent = async () => {
    setIsLoadingText(true);
    setError(null);
    resetAudioState();
    try {
      const rawText = await extractChapterText(fileContext, chapter);
      const cleanText = rearrangeAndCleanText(rawText);
      const paginated = paginateText(cleanText, PAGE_TARGET_SIZE);
      setPages(paginated);
    } catch (err: any) {
      setError(err.message || "Failed to extract text.");
    } finally {
      setIsLoadingText(false);
    }
  };

  useEffect(() => { loadContent(); }, [chapter, fileContext]);

  useEffect(() => {
     if (!pages[currentPage]) return;
     const pageText = pages[currentPage];
     const rawParagraphs = pageText.split(/\n\s*\n/).filter(p => p.trim().length > 0);
     const newParagraphData: ParagraphData[] = [];
     const newSentenceMap: SentenceMap[] = [];
     let globalIdx = 0;
     rawParagraphs.forEach((pText, pIndex) => {
         const sentences = splitIntoSentences(pText).map(s => s.trim()).filter(s => s.length > 0);
         sentences.forEach((s, sIndex) => {
             newSentenceMap.push({ pIndex, sIndex, globalIndex: globalIdx, text: s });
             globalIdx++;
         });
         newParagraphData.push({ original: sentences, translated: [] });
     });
     setParagraphData(newParagraphData);
     setFlatSentenceMap(newSentenceMap);
     resetAudioState();
     abortGenerationRef.current = true;
     if (nextAutoGenerateRef.current) {
         nextAutoGenerateRef.current = false;
         generatePageAudio();
     }
  }, [currentPage, pages]);

  useEffect(() => {
    const loadTranslation = async () => {
      if (viewMode === 'split' && pages[currentPage]) {
        setIsTranslating(true);
        try {
          const translatedText = await translateText(pages[currentPage], settings.targetLanguage);
          const rawTransParagraphs = rearrangeAndCleanText(translatedText).split(/\n\s*\n/).filter(p => p.trim().length > 0);
          const isChineseTarget = settings.targetLanguage.includes("Chinese");
          setParagraphData(prev => prev.map((p, idx) => ({ 
            ...p, translated: splitIntoSentences(rawTransParagraphs[idx] || "", isChineseTarget) 
          })));
        } catch(e) { console.error(e); } finally { setIsTranslating(false); }
      }
    };
    loadTranslation();
  }, [currentPage, viewMode, settings.targetLanguage, pages]);

  useEffect(() => {
    if (audioRef.current) audioRef.current.playbackRate = playbackRate;
  }, [playbackRate]);

  useEffect(() => {
    let animationFrameId: number;
    const syncPlayback = () => {
        if (!audioRef.current) return;
        const t = audioRef.current.currentTime;
        const d = audioRef.current.duration;
        setCurrentTime(t);
        setDuration(d || 0);
        setPlaybackProgress((t / (d || 1)) * 100);
        const activeIdx = timings.findIndex(chunk => !chunk.isWhitespace && t >= chunk.start && t < chunk.end);
        if (activeIdx !== -1 && activeIdx !== activeSentenceIndex) setActiveSentenceIndex(activeIdx);
        if (isPlaying) animationFrameId = requestAnimationFrame(syncPlayback);
    };
    if (isPlaying) animationFrameId = requestAnimationFrame(syncPlayback);
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, timings, activeSentenceIndex]);

  useEffect(() => {
    if (!autoScroll) return;
    if (activeSentenceIndex !== -1 && flatSentenceMap[activeSentenceIndex]) {
        const sentenceEl = document.getElementById(`original-sent-${activeSentenceIndex}`);
        if (sentenceEl) {
             isProgrammaticScroll.current = true;
             sentenceEl.scrollIntoView({ behavior: 'smooth', block: 'center', inline: 'nearest' });
             const scrollTimeout = setTimeout(() => { isProgrammaticScroll.current = false; }, 800);
            return () => clearTimeout(scrollTimeout);
        }
    }
  }, [activeSentenceIndex, autoScroll, flatSentenceMap]);

  const generatePageAudio = async () => {
    if (isGenerating || !flatSentenceMap.length) return;
    abortGenerationRef.current = false;
    setIsGenerating(true);
    setGenerationProgress("INIT_CORE...");
    try {
      const sentences = flatSentenceMap.map(m => m.text);
      const audioResults = await processQueue<string, string | null>(
        sentences, CONCURRENCY_LIMIT, 
        async (sentence, idx) => {
           if (abortGenerationRef.current) return null;
           setGenerationProgress(`PACKET_${idx + 1}_OF_${sentences.length}`);
           return await generateSpeech(sentence, selectedVoice);
        },
        () => abortGenerationRef.current
      );
      if (abortGenerationRef.current) return;
      const audioBuffers: Uint8Array[] = [];
      const newTimings: ChunkTiming[] = [];
      let currentOffset = 0;
      const BYTES_PER_SEC = 48000; 
      for (let i = 0; i < sentences.length; i++) {
        const b64 = audioResults[i];
        if (!b64) {
          newTimings.push({ text: sentences[i], start: currentOffset / BYTES_PER_SEC, end: currentOffset / BYTES_PER_SEC, isWhitespace: true });
          continue;
        }
        const binaryString = atob(b64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let k = 0; k < len; k++) bytes[k] = binaryString.charCodeAt(k);
        audioBuffers.push(bytes);
        const startSec = currentOffset / BYTES_PER_SEC;
        const durationSec = len / BYTES_PER_SEC;
        newTimings.push({ text: sentences[i], start: startSec, end: startSec + durationSec, isWhitespace: false });
        currentOffset += len;
      }
      const mergedBuffer = new Uint8Array(currentOffset);
      let offset = 0;
      for (const buf of audioBuffers) { mergedBuffer.set(buf, offset); offset += buf.length; }
      const wavHeader = new ArrayBuffer(44);
      const view = new DataView(wavHeader);
      const writeStr = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
      writeStr(view, 0, 'RIFF'); view.setUint32(4, 36 + currentOffset, true); writeStr(view, 8, 'WAVE');
      writeStr(view, 12, 'fmt '); view.setUint32(16, 16, true); view.setUint16(20, 1, true); view.setUint16(22, 1, true);
      view.setUint32(24, 24000, true); view.setUint32(28, 48000, true); view.setUint16(32, 2, true); view.setUint16(34, 16, true);
      writeStr(view, 36, 'data'); view.setUint32(40, currentOffset, true);
      const blob = new Blob([wavHeader, mergedBuffer], { type: 'audio/wav' });
      setTimings(newTimings); 
      setAudioSrc(URL.createObjectURL(blob));
      setIsPlaying(true);
    } catch (e: any) {
      setGenerationProgress("ERR: " + e.message);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAudioEnded = () => {
      setIsPlaying(false);
      if (autoFlip && currentPage < pages.length - 1) {
          nextAutoGenerateRef.current = true;
          setCurrentPage(prev => prev + 1);
      }
  };

  const togglePlay = () => {
    if (!audioSrc) { generatePageAudio(); return; }
    if (audioRef.current) { isPlaying ? audioRef.current.pause() : audioRef.current.play(); }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (audioRef.current && duration) {
       const newTime = (val / 100) * duration;
       audioRef.current.currentTime = newTime;
       setPlaybackProgress(val);
       setCurrentTime(newTime);
    }
  };

  const changePage = (delta: number) => {
    const newPage = currentPage + delta;
    if (newPage >= 0 && newPage < pages.length) setCurrentPage(newPage);
  };

  const highlightSearch = (text: string) => {
      if (!searchQuery.trim()) return text;
      const regex = new RegExp(`(${escapeRegExp(searchQuery)})`, 'gi');
      const parts = text.split(regex);
      return parts.map((part, i) => part.toLowerCase() === searchQuery.toLowerCase() ? (
          <span key={i} className="bg-[#ff003c] text-white rounded-sm px-0.5">{part}</span>
      ) : part);
  };

  const canPrev = currentPage > 0;
  const canNext = currentPage < pages.length - 1;
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };

  return (
    <div className="h-full flex flex-col gap-4 animate-fade-in font-sans text-zinc-100" style={fontStyle}>

      {/* 1. SMART AUDIO READ CONTROL AREA */}
      <div className="bg-zinc-950/80 p-3 rounded-lg border border-zinc-900 mb-0 flex items-center justify-between shrink-0 shadow-lg flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Volume2 size={16} className="text-[#00f3ff]" />
                 <span>VOICE_SYNTH_PROTOCOL</span>
              </div>
          </div>

          <div className="flex items-center gap-2">
              {/* Voice and Language Group */}
              <div className="flex items-center bg-[#050505] p-0.5 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500" title="Tone Core"><Settings2 size={14} /></div>
                 <select 
                    value={selectedVoice} 
                    onChange={(e) => { setSelectedVoice(e.target.value); resetAudioState(); }}
                    className="bg-[#050505] text-[10px] text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-32 py-1"
                 >
                    {VOICES.map(v => <option key={v.id} value={v.id}>{v.name} [{v.label}]</option>)}
                 </select>
                 <div className="w-[1px] h-3 bg-zinc-700 mx-1"></div>
                 <div className="p-1.5 text-zinc-500" title="Target Locale"><Globe size={14} /></div>
                 <select 
                    value={settings.targetLanguage} 
                    onChange={(e) => onSettingsUpdate({ ...settings, targetLanguage: e.target.value })}
                    className="bg-[#050505] text-[10px] text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-28 py-1"
                 >
                    {LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                 </select>
              </div>

              {/* Action Group */}
              <div className="flex items-center gap-2">
                  <button 
                    onClick={() => setAutoFlip(!autoFlip)}
                    className={`h-full px-3 py-1.5 rounded-sm text-[10px] font-bold uppercase tracking-wider font-mono flex items-center gap-2 transition-all border ${autoFlip ? 'bg-[#00f3ff]/10 border-[#00f3ff] text-[#00f3ff]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-zinc-300'}`}
                    title="Toggle Continuous Page Flow"
                  >
                     <Repeat size={14} /> {autoFlip ? 'ON' : 'OFF'}
                  </button>
                  <button 
                    onClick={generatePageAudio} 
                    disabled={isGenerating} 
                    className={`h-full px-4 py-1.5 rounded-sm text-[10px] font-bold uppercase tracking-wider font-mono flex items-center gap-2 transition-all border ${isGenerating ? 'bg-zinc-800 text-zinc-600' : 'bg-[#00f3ff] text-black border-[#00f3ff] hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.3)]'} disabled:opacity-50`}
                  >
                     {isGenerating ? <LoaderIcon className="animate-spin" size={12} /> : <Mic2 size={12} />}
                     {isGenerating ? generationProgress : "GENERATE_AUDIO"}
                  </button>
              </div>
          </div>
       </div>

      {/* 2. ENHANCED PLAYER AREA (CENTER) */}
      <div className="bg-[#0a0a0c] border border-zinc-800 rounded-lg p-6 flex flex-col items-center justify-center shadow-2xl relative overflow-hidden shrink-0 w-full max-w-5xl mx-auto group">
          <div className="absolute inset-0 bg-[linear-gradient(to_right,#18181b_1px,transparent_1px),linear-gradient(to_bottom,#18181b_1px,transparent_1px)] bg-[size:32px_32px] opacity-20 pointer-events-none"></div>

          {/* Vinyl Area */}
          <div className="flex items-center justify-center py-4 relative">
              <div className={`w-44 h-44 rounded-full border-4 border-zinc-900 shadow-[0_0_50px_rgba(0,0,0,0.9)] relative flex items-center justify-center bg-black overflow-hidden ${isPlaying ? 'animate-spin-slow' : ''}`}>
                  <div className="absolute inset-0 opacity-40 bg-[repeating-radial-gradient(circle,transparent,transparent_2px,#27272a_3px)]"></div>
                  <div className="w-14 h-14 rounded-full bg-[#050505] border border-zinc-800 flex items-center justify-center relative z-10">
                      <Cpu className={`text-[#00f3ff] ${isPlaying ? 'animate-pulse' : ''}`} size={24} />
                  </div>
              </div>
          </div>

          {/* Progress Bar */}
          <div className="w-full mt-6 flex items-center gap-4 relative z-10 px-4">
              <span className="text-[10px] font-mono text-zinc-500 min-w-[35px] text-right">{formatTime(currentTime)}</span>
              <div className="flex-1 relative h-6 flex items-center group/scrub cursor-pointer">
                  <div className="absolute w-full h-1 bg-zinc-900 rounded-full overflow-hidden border border-zinc-800">
                      <div className="h-full bg-[#00f3ff] shadow-[0_0_10px_#00f3ff]" style={{ width: `${playbackProgress}%` }}></div>
                  </div>
                  <input 
                    type="range" min="0" max="100" step="0.1" value={playbackProgress} onChange={handleSeek} disabled={!audioSrc}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" 
                  />
                  <div className="absolute top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover/scrub:opacity-100 transition-opacity shadow-lg pointer-events-none" style={{ left: `${playbackProgress}%`, transform: 'translateX(-50%) translateY(-50%)' }}></div>
              </div>
              <span className="text-[10px] font-mono text-zinc-500 min-w-[35px]">{formatTime(duration)}</span>
          </div>

          {/* Player Footer */}
          <div className="w-full mt-6 flex items-center justify-between border-t border-zinc-900/50 pt-4 z-10 px-4">
              {/* Parallel Radio Speed Buttons */}
              <div className="flex items-center gap-2">
                  {SPEEDS.map(s => (
                      <button 
                        key={s} 
                        onClick={() => setPlaybackRate(s)}
                        className={`text-[9px] font-bold font-mono transition-all px-1.5 py-1 ${playbackRate === s ? 'text-[#00f3ff] bg-[#00f3ff]/10 rounded-sm' : 'text-zinc-600 hover:text-zinc-400'}`}
                      >
                          {s.toFixed(1)}x
                      </button>
                  ))}
              </div>

              {/* Main Playback Controls (Center) */}
              <div className="flex items-center gap-8 absolute left-1/2 -translate-x-1/2">
                  <button onClick={() => audioRef.current && (audioRef.current.currentTime -= 10)} disabled={!audioSrc} className="text-zinc-500 hover:text-white transition-colors"><RotateCcw size={18} /></button>
                  <button 
                    onClick={togglePlay} 
                    disabled={isGenerating}
                    className={`w-12 h-12 rounded-full flex items-center justify-center border-2 transition-all hover:scale-105 active:scale-95 ${isPlaying ? 'bg-black/50 border-[#00f3ff] text-[#00f3ff] shadow-[0_0_20px_rgba(0,243,255,0.2)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_25px_rgba(0,243,255,0.4)]'}`}
                  >
                      {isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" className="ml-1" />}
                  </button>
                  <button onClick={() => audioRef.current && (audioRef.current.currentTime += 10)} disabled={!audioSrc} className="text-zinc-500 hover:text-white transition-colors"><RotateCw size={18} /></button>
              </div>

              {/* Download (Far Right) */}
              <div className="w-32 flex justify-end">
                  {audioSrc ? (
                    <a href={audioSrc} download={`decod-audio-ch${chapter.id}-pg${currentPage+1}.wav`} className="flex items-center gap-2 px-3 py-1.5 bg-zinc-900 border border-zinc-800 rounded-sm text-zinc-400 hover:text-[#00f3ff] transition-all text-[9px] font-bold font-mono uppercase tracking-widest">
                        <Download size={14} /> Download
                    </a>
                  ) : (
                    <button disabled className="flex items-center gap-2 px-3 py-1.5 bg-zinc-900/50 border border-zinc-900 rounded-sm text-zinc-700 text-[9px] font-bold font-mono uppercase cursor-not-allowed">
                        <Download size={14} /> Download
                    </button>
                  )}
              </div>
          </div>

          {audioSrc && (
            <audio 
                ref={audioRef} src={audioSrc} crossOrigin="anonymous" 
                onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} onEnded={handleAudioEnded} 
                className="hidden" 
            />
          )}
      </div>

      {/* 3. MAIN CONTENT AREA */}
      <div className="flex-1 overflow-hidden rounded-lg border border-zinc-800 bg-[#050505] relative flex flex-col hud-border shadow-lg mt-0">
         <div className="flex shrink-0 border-b border-zinc-800 bg-[#0a0a0c]/90 backdrop-blur-md z-10 w-full flex-col">
            <div className="flex items-center justify-between p-2">
                 <div className="flex items-center gap-2">
                    <button onClick={() => changePage(-1)} disabled={!canPrev} className="p-1.5 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] hover:text-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all"><ChevronLeft size={14} /></button>
                    <div className="text-center min-w-[60px]"><h3 className="text-[10px] font-bold text-[#00f3ff] uppercase tracking-widest font-tech">PG.{String(currentPage + 1).padStart(2,'0')}</h3></div>
                    <button onClick={() => changePage(1)} disabled={!canNext} className="p-1.5 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] hover:text-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all"><ChevronRight size={14} /></button>
                </div>

                 {/* Centered Search */}
                 <div className="flex items-center gap-2 bg-zinc-950 border border-zinc-900 px-3 py-1 rounded-sm mx-auto flex-1 max-w-sm focus-within:border-[#00f3ff]/50 transition-colors">
                    <Search size={12} className="text-zinc-600" />
                    <input 
                        type="text" placeholder="SEARCH_NEURAL_BLOCK..." value={searchQuery} 
                        onChange={(e) => setSearchQuery(e.target.value)} 
                        className="bg-transparent text-[10px] text-[#00f3ff] focus:outline-none w-full font-mono placeholder:text-zinc-700 uppercase text-center" 
                    />
                 </div>

                 <div className="flex items-center gap-2">
                    <button onClick={() => setViewMode(viewMode === 'split' ? 'single' : 'split')} className={`flex items-center gap-1 px-2 py-1 rounded-sm text-[9px] font-bold font-tech transition-all border ${viewMode === 'split' ? 'bg-[#00f3ff]/10 border-[#00f3ff] text-[#00f3ff]' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
                        {viewMode === 'split' ? <SplitSquareHorizontal size={12} /> : <Columns size={12} />} SPLIT
                    </button>
                    <button onClick={() => setAutoScroll(!autoScroll)} className={`flex items-center gap-1 px-2 py-1 rounded-sm text-[9px] font-bold font-tech transition-all border ${autoScroll ? 'bg-emerald-900/20 border-emerald-500 text-emerald-400' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
                        {autoScroll ? <Eye size={12} /> : <EyeOff size={12} />} TRACK
                    </button>
                 </div>
            </div>
         </div>

         <div className="flex-1 overflow-y-auto scroll-smooth custom-scrollbar relative p-4 pb-48">
             <div className={`flex flex-col gap-8 ${viewMode === 'split' ? '' : 'items-center'}`}>
                {paragraphData.map((para, pIdx) => (
                    <div key={pIdx} className={`w-full ${viewMode === 'split' ? 'flex' : 'max-w-4xl flex flex-col'} p-2`}>
                        <div className={`${viewMode === 'split' ? 'w-1/2 pr-6 border-r border-zinc-800/50' : 'w-full'} ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} text-zinc-400 whitespace-pre-wrap`}>
                            {para.original.map((sentence, sIdx) => {
                                const m = flatSentenceMap.find(sm => sm.pIndex === pIdx && sm.sIndex === sIdx);
                                const globalIdx = m?.globalIndex ?? -1;
                                const isActive = autoScroll && globalIdx === activeSentenceIndex;
                                return (
                                    <span key={sIdx} id={`original-sent-${globalIdx}`} className={`transition-all duration-300 px-[2px] ${isActive ? HIGHLIGHT_STYLES[settings.highlightColor] : 'hover:text-zinc-200'}`}>
                                        {highlightSearch(sentence)}{' '}
                                    </span>
                                );
                            })}
                        </div>
                        {viewMode === 'split' && (
                            <div className={`w-1/2 pl-6 ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} text-zinc-500 whitespace-pre-wrap`}>
                                {para.translated.map((tSent, tIdx) => (
                                    <span key={tIdx} className="px-[2px]">{tSent}{' '}</span>
                                ))}
                            </div>
                        )}
                    </div>
                ))}
             </div>
         </div>
      </div>
    </div>
  );
};

