const formatTime = (seconds: number): string => {
  if (!seconds || isNaN(seconds)) return "00:00";
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
};

const rearrangeAndCleanText = (text: string): string => {
  if (!text) return "";
  let cleaned = text;
  cleaned = cleaned.replace(/(\w)-\n(\w)/g, '$1$2');
  const paragraphs = cleaned.split(/\n\s*\n/);
  const processedParagraphs = paragraphs.map(p => p.replace(/\n/g, ' ').trim());
  return processedParagraphs.join('\n\n');
};

const paginateText = (text: string, targetSize: number): string[] => {
  const pages: string[] = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= targetSize) {
      pages.push(remaining.trim());
      break;
    }
    let splitIdx = targetSize;
    const paragraphBreak = remaining.lastIndexOf('\n\n', targetSize);
    if (paragraphBreak > targetSize * 0.7) splitIdx = paragraphBreak;
    else {
      const sentenceBreak = Math.max(
          remaining.lastIndexOf('. ', targetSize),
          remaining.lastIndexOf('? ', targetSize),
          remaining.lastIndexOf('! ', targetSize)
      );
      if (sentenceBreak > targetSize * 0.5) splitIdx = sentenceBreak + 1;
      else {
          const spaceBreak = remaining.lastIndexOf(' ', targetSize);
          if (spaceBreak > 0) splitIdx = spaceBreak;
      }
    }
    pages.push(remaining.substring(0, splitIdx).trim());
    remaining = remaining.substring(splitIdx).trim();
  }
  return pages;
};

const splitIntoSentences = (text: string, isChinese: boolean = false): string[] => {
  if (!text) return [];
  if (isChinese) return text.match(/[^。！？]+[。！？]+|[^。！？]+$/g) || [text];
  return text.match(/[^.!?]+[.!?]+(\s+|$)|[^.!?]+$/g) || [text];
};

const escapeRegExp = (string: string) => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const processQueue = async <T, R>(
  items: T[],
  concurrency: number,
  fn: (item: T, index: number) => Promise<R>,
  checkAbort?: () => boolean
): Promise<(R | null)[]> => {
  const results: (R | null)[] = new Array(items.length).fill(null);
  const queue = [...items.map((item, index) => ({ item, index }))];
  const worker = async () => {
    while (queue.length > 0) {
      if (checkAbort && checkAbort()) break;
      const task = queue.shift();
      if (!task) break; 
      const { item, index } = task;
      try {
        const result = await fn(item, index);
        results[index] = result;
        await new Promise(resolve => setTimeout(resolve, 300)); 
      } catch (e: any) {
        results[index] = null;
      }
    }
  };
  const workers = Array.from({ length: concurrency }).map(() => worker());
  await Promise.all(workers);
  return results;
};

export const AudioBook: React.FC<Props> = ({ chapter, fileContext, settings, onSettingsUpdate }) => {
  const [pages, setPages] = useState<string[]>([]);
  const [paragraphData, setParagraphData] = useState<ParagraphData[]>([]);
  const [flatSentenceMap, setFlatSentenceMap] = useState<SentenceMap[]>([]);
  const [currentPage, setCurrentPage] = useState(0);
  const [isLoadingText, setIsLoadingText] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [viewMode, setViewMode] = useState<'single' | 'split'>('single');
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [timings, setTimings] = useState<ChunkTiming[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generationProgress, setGenerationProgress] = useState("");
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [selectedVoice, setSelectedVoice] = useState('Puck');
  const [autoScroll, setAutoScroll] = useState(true);
  const [autoFlip, setAutoFlip] = useState(false);
  const [activeSentenceIndex, setActiveSentenceIndex] = useState<number>(-1);
  const [searchQuery, setSearchQuery] = useState("");

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const abortGenerationRef = useRef<boolean>(false);
  const isProgrammaticScroll = useRef(false);
  const nextAutoGenerateRef = useRef<boolean>(false);

  const resetAudioState = () => {
    setAudioSrc(null);
    setTimings([]);
    setIsPlaying(false);
    setPlaybackProgress(0);
    setCurrentTime(0);
    setDuration(0);
    setActiveSentenceIndex(-1);
    setGenerationProgress("");
  };

  const loadContent = async () => {
    setIsLoadingText(true);
    setError(null);
    resetAudioState();
    try {
      const rawText = await extractChapterText(fileContext, chapter);
      const cleanText = rearrangeAndCleanText(rawText);
      const paginated = paginateText(cleanText, PAGE_TARGET_SIZE);
      setPages(paginated);
    } catch (err: any) {
      setError(err.message || "Failed to extract neural block.");
    } finally {
      setIsLoadingText(false);
    }
  };

  useEffect(() => { loadContent(); }, [chapter, fileContext]);

  useEffect(() => {
     if (!pages[currentPage]) return;
     const pageText = pages[currentPage];
     const rawParagraphs = pageText.split(/\n\s*\n/).filter(p => p.trim().length > 0);
     const newParagraphData: ParagraphData[] = [];
     const newSentenceMap: SentenceMap[] = [];
     let globalIdx = 0;
     rawParagraphs.forEach((pText, pIndex) => {
         const sentences = splitIntoSentences(pText).map(s => s.trim()).filter(s => s.length > 0);
         sentences.forEach((s, sIndex) => {
             newSentenceMap.push({ pIndex, sIndex, globalIndex: globalIdx, text: s });
             globalIdx++;
         });
         newParagraphData.push({ original: sentences, translated: [] });
     });
     setParagraphData(newParagraphData);
     setFlatSentenceMap(newSentenceMap);
     resetAudioState();
     abortGenerationRef.current = true;
     if (nextAutoGenerateRef.current) {
         nextAutoGenerateRef.current = false;
         generatePageAudio();
     }
  }, [currentPage, pages]);

  useEffect(() => {
    const loadTranslation = async () => {
      if (viewMode === 'split' && pages[currentPage]) {
        setIsTranslating(true);
        try {
          const translatedText = await translateText(pages[currentPage], settings.targetLanguage);
          const rawTransParagraphs = rearrangeAndCleanText(translatedText).split(/\n\s*\n/).filter(p => p.trim().length > 0);
          const isChineseTarget = settings.targetLanguage.includes("Chinese");
          setParagraphData(prev => prev.map((p, idx) => ({ 
            ...p, translated: splitIntoSentences(rawTransParagraphs[idx] || "", isChineseTarget) 
          })));
        } catch(e) { console.error(e); } finally { setIsTranslating(false); }
      }
    };
    loadTranslation();
  }, [currentPage, viewMode, settings.targetLanguage, pages]);

  useEffect(() => {
    if (audioRef.current) audioRef.current.playbackRate = playbackRate;
  }, [playbackRate]);

  useEffect(() => {
    let animationFrameId: number;
    const syncPlayback = () => {
        if (!audioRef.current) return;
        const t = audioRef.current.currentTime;
        const d = audioRef.current.duration;
        setCurrentTime(t);
        setDuration(d || 0);
        setPlaybackProgress((t / (d || 1)) * 100);
        const activeIdx = timings.findIndex(chunk => !chunk.isWhitespace && t >= chunk.start && t < chunk.end);
        if (activeIdx !== -1 && activeIdx !== activeSentenceIndex) setActiveSentenceIndex(activeIdx);
        if (isPlaying) animationFrameId = requestAnimationFrame(syncPlayback);
    };
    if (isPlaying) animationFrameId = requestAnimationFrame(syncPlayback);
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, timings, activeSentenceIndex]);

  useEffect(() => {
    if (!autoScroll) return;
    if (activeSentenceIndex !== -1 && flatSentenceMap[activeSentenceIndex]) {
        const sentenceEl = document.getElementById(`original-sent-${activeSentenceIndex}`);
        if (sentenceEl) {
             isProgrammaticScroll.current = true;
             sentenceEl.scrollIntoView({ behavior: 'smooth', block: 'center', inline: 'nearest' });
             const scrollTimeout = setTimeout(() => { isProgrammaticScroll.current = false; }, 800);
            return () => clearTimeout(scrollTimeout);
        }
    }
  }, [activeSentenceIndex, autoScroll, flatSentenceMap]);

  const generatePageAudio = async () => {
    if (isGenerating || !flatSentenceMap.length) return;
    abortGenerationRef.current = false;
    setIsGenerating(true);
    setGenerationProgress("INIT_CORE...");
    try {
      const sentences = flatSentenceMap.map(m => m.text);
      const audioResults = await processQueue<string, string | null>(
        sentences, CONCURRENCY_LIMIT, 
        async (sentence, idx) => {
           if (abortGenerationRef.current) return null;
           setGenerationProgress(`PACKET_${idx + 1}_OF_${sentences.length}`);
           return await generateSpeech(sentence, selectedVoice);
        },
        () => abortGenerationRef.current
      );
      if (abortGenerationRef.current) return;
      const audioBuffers: Uint8Array[] = [];
      const newTimings: ChunkTiming[] = [];
      let currentOffset = 0;
      const BYTES_PER_SEC = 48000; 
      for (let i = 0; i < sentences.length; i++) {
        const b64 = audioResults[i];
        if (!b64) {
          newTimings.push({ text: sentences[i], start: currentOffset / BYTES_PER_SEC, end: currentOffset / BYTES_PER_SEC, isWhitespace: true });
          continue;
        }
        const binaryString = atob(b64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let k = 0; k < len; k++) bytes[k] = binaryString.charCodeAt(k);
        audioBuffers.push(bytes);
        const startSec = currentOffset / BYTES_PER_SEC;
        const durationSec = len / BYTES_PER_SEC;
        newTimings.push({ text: sentences[i], start: startSec, end: startSec + durationSec, isWhitespace: false });
        currentOffset += len;
      }
      const mergedBuffer = new Uint8Array(currentOffset);
      let offset = 0;
      for (const buf of audioBuffers) { mergedBuffer.set(buf, offset); offset += buf.length; }
      const wavHeader = new ArrayBuffer(44);
      const view = new DataView(wavHeader);
      const writeStr = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
      writeStr(view, 0, 'RIFF'); view.setUint32(4, 36 + currentOffset, true); writeStr(view, 8, 'WAVE');
      writeStr(view, 12, 'fmt '); view.setUint32(16, 16, true); view.setUint16(20, 1, true); view.setUint16(22, 1, true);
      view.setUint32(24, 24000, true); view.setUint32(28, 48000, true); view.setUint16(32, 2, true); view.setUint16(34, 16, true);
      writeStr(view, 36, 'data'); view.setUint32(40, currentOffset, true);
      const blob = new Blob([wavHeader, mergedBuffer], { type: 'audio/wav' });
      setTimings(newTimings); 
      setAudioSrc(URL.createObjectURL(blob));
      setIsPlaying(true);
    } catch (e: any) {
      setGenerationProgress("ERR: " + e.message);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAudioEnded = () => {
      setIsPlaying(false);
      if (autoFlip && currentPage < pages.length - 1) {
          nextAutoGenerateRef.current = true;
          setCurrentPage(prev => prev + 1);
      }
  };

  const togglePlay = () => {
    if (!audioSrc) { generatePageAudio(); return; }
    if (audioRef.current) { isPlaying ? audioRef.current.pause() : audioRef.current.play(); }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (audioRef.current && duration) {
       const newTime = (val / 100) * duration;
       audioRef.current.currentTime = newTime;
       setPlaybackProgress(val);
       setCurrentTime(newTime);
    }
  };

  const changePage = (delta: number) => {
    const newPage = currentPage + delta;
    if (newPage >= 0 && newPage < pages.length) setCurrentPage(newPage);
  };

  const highlightSearch = (text: string) => {
      if (!searchQuery.trim()) return text;
      const regex = new RegExp(`(${escapeRegExp(searchQuery)})`, 'gi');
      const parts = text.split(regex);
      return parts.map((part, i) => part.toLowerCase() === searchQuery.toLowerCase() ? (
          <span key={i} className="bg-[#ff003c] text-white rounded-sm px-0.5">{part}</span>
      ) : part);
  };

  const canPrev = currentPage > 0;
  const canNext = currentPage < pages.length - 1;
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };

  return (
    <div className="h-full flex flex-col gap-4 animate-fade-in font-sans text-zinc-100" style={fontStyle}>

      {/* 1. SMART AUDIO READ CONTROL AREA (NET_CAST Layout Style) */}
      <div className="bg-zinc-950/80 p-3 rounded-lg border border-zinc-900 mb-0 flex items-center justify-between shrink-0 shadow-lg flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Volume2 size={16} className="text-[#00f3ff]" />
                 <span>NET_CAST_PROTOCOL</span>
              </div>
          </div>

          <div className="flex items-center gap-2">
              {/* Tone (Voice) and Language Group */}
              <div className="flex items-center bg-[#050505] p-0.5 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500" title="Tone Core"><Settings2 size={14} /></div>
                 <select 
                    value={selectedVoice} 
                    onChange={(e) => { setSelectedVoice(e.target.value); resetAudioState(); }}
                    className="bg-[#050505] text-[10px] text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-32 py-1"
                 >
                    {VOICES.map(v => <option key={v.id} value={v.id}>{v.name} [{v.label}]</option>)}
                 </select>
                 <div className="w-[1px] h-3 bg-zinc-700 mx-1"></div>
                 <div className="p-1.5 text-zinc-500" title="Target Locale"><Globe size={14} /></div>
                 <select 
                    value={settings.targetLanguage} 
                    onChange={(e) => onSettingsUpdate({ ...settings, targetLanguage: e.target.value })}
                    className="bg-[#050505] text-[10px] text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-28 py-1"
                 >
                    {LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                 </select>
              </div>

              {/* Action Group */}
              <div className="flex items-center gap-2">
                  <button 
                    onClick={() => setAutoFlip(!autoFlip)}
                    className={`h-full px-3 py-1.5 rounded-sm text-[10px] font-bold uppercase tracking-wider font-mono flex items-center gap-2 transition-all border ${autoFlip ? 'bg-[#ff003c]/10 border-[#ff003c] text-[#ff003c]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-zinc-300'}`}
                    title="Toggle Continuous Page Flow"
                  >
                     <Repeat size={14} /> {autoFlip ? 'ON' : 'OFF'}
                  </button>
                  <button 
                    onClick={generatePageAudio} 
                    disabled={isGenerating} 
                    className={`h-full px-4 py-1.5 rounded-sm text-[10px] font-bold uppercase tracking-wider font-mono flex items-center gap-2 transition-all border ${isGenerating ? 'bg-zinc-800 text-zinc-600' : 'bg-[#00f3ff] text-black border-[#00f3ff] hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.3)]'} disabled:opacity-50`}
                  >
                     {isGenerating ? <LoaderIcon className="animate-spin" size={12} /> : <Mic2 size={12} />}
                     {isGenerating ? generationProgress : "GENERATE_AUDIO"}
                  </button>
              </div>
          </div>
       </div>

      {/* 2. ENHANCED PLAYER AREA (CENTER) */}
      <div className="bg-[#0a0a0c] border border-zinc-800 rounded-lg p-6 flex flex-col items-center justify-center shadow-2xl relative overflow-hidden shrink-0 w-full max-w-5xl mx-auto group">
          <div className="absolute inset-0 bg-[linear-gradient(to_right,#18181b_1px,transparent_1px),linear-gradient(to_bottom,#18181b_1px,transparent_1px)] bg-[size:32px_32px] opacity-20 pointer-events-none"></div>

          {/* Vinyl Area */}
          <div className="flex items-center justify-center py-4 relative">
              <div className={`w-44 h-44 rounded-full border-4 border-zinc-900 shadow-[0_0_50px_rgba(0,0,0,0.9)] relative flex items-center justify-center bg-black overflow-hidden ${isPlaying ? 'animate-spin-slow' : ''}`}>
                  <div className="absolute inset-0 opacity-40 bg-[repeating-radial-gradient(circle,transparent,transparent_2px,#27272a_3px)]"></div>
                  <div className="w-14 h-14 rounded-full bg-[#050505] border border-zinc-800 flex items-center justify-center relative z-10">
                      <Cpu className={`text-[#00f3ff] ${isPlaying ? 'animate-pulse' : ''}`} size={24} />
                  </div>
              </div>
          </div>

          {/* Progress Bar with Free Scrubbing */}
          <div className="w-full mt-6 flex items-center gap-4 relative z-10 px-4">
              <span className="text-[10px] font-mono text-zinc-500 min-w-[35px] text-right">{formatTime(currentTime)}</span>
              <div className="flex-1 relative h-6 flex items-center group/scrub cursor-pointer">
                  <div className="absolute w-full h-1 bg-zinc-900 rounded-full overflow-hidden border border-zinc-800">
                      <div className="h-full bg-[#00f3ff] shadow-[0_0_10px_#00f3ff]" style={{ width: `${playbackProgress}%` }}></div>
                  </div>
                  <input 
                    type="range" min="0" max="100" step="0.1" value={playbackProgress} onChange={handleSeek} disabled={!audioSrc}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" 
                  />
                  <div className="absolute top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover/scrub:opacity-100 transition-opacity shadow-lg pointer-events-none" style={{ left: `${playbackProgress}%`, transform: 'translateX(-50%) translateY(-50%)' }}></div>
              </div>
              <span className="text-[10px] font-mono text-zinc-500 min-w-[35px]">{formatTime(duration)}</span>
          </div>

          {/* Player Footer */}
          <div className="w-full mt-6 flex items-center justify-between border-t border-zinc-900/50 pt-4 z-10 px-4">

              {/* Parallel Radio Speed Buttons (Bottom Left) */}
              <div className="flex items-center gap-2">
                  {SPEEDS.map(s => (
                      <button 
                        key={s} 
                        onClick={() => setPlaybackRate(s)}
                        className={`text-[9px] font-bold font-mono transition-all px-2 py-1 rounded-sm border ${playbackRate === s ? 'text-[#00f3ff] bg-[#00f3ff]/10 border-[#00f3ff]/30' : 'text-zinc-600 hover:text-zinc-400 border-transparent'}`}
                      >
                          {s.toFixed(1)}x
                      </button>
                  ))}
              </div>

              {/* Main Playback Controls (Center) */}
              <div className="flex items-center gap-8 absolute left-1/2 -translate-x-1/2">
                  <button onClick={() => audioRef.current && (audioRef.current.currentTime -= 10)} disabled={!audioSrc} className="text-zinc-500 hover:text-white transition-colors"><RotateCcw size={18} /></button>
                  <button 
                    onClick={togglePlay} 
                    disabled={isGenerating}
                    className={`w-12 h-12 rounded-full flex items-center justify-center border-2 transition-all hover:scale-105 active:scale-95 ${isPlaying ? 'bg-black/50 border-[#00f3ff] text-[#00f3ff] shadow-[0_0_20px_rgba(0,243,255,0.2)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_25px_rgba(0,243,255,0.4)]'}`}
                  >
                      {isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" className="ml-1" />}
                  </button>
                  <button onClick={() => audioRef.current && (audioRef.current.currentTime += 10)} disabled={!audioSrc} className="text-zinc-500 hover:text-white transition-colors"><RotateCw size={18} /></button>
              </div>

              {/* Download (Far Right) */}
              <div className="w-32 flex justify-end">
                  {audioSrc ? (
                    <a href={audioSrc} download={`decod-audio-ch${chapter.id}-pg${currentPage+1}.wav`} className="flex items-center gap-2 px-3 py-1.5 bg-zinc-900 border border-zinc-800 rounded-sm text-zinc-400 hover:text-[#00f3ff] transition-all text-[9px] font-bold font-mono uppercase tracking-widest">
                        <Download size={14} /> Download
                    </a>
                  ) : (
                    <button disabled className="flex items-center gap-2 px-3 py-1.5 bg-zinc-900/50 border border-zinc-900 rounded-sm text-zinc-700 text-[9px] font-bold font-mono uppercase cursor-not-allowed">
                        <Download size={14} /> Download
                    </button>
                  )}
              </div>
          </div>

          {audioSrc && (
            <audio 
                ref={audioRef} src={audioSrc} crossOrigin="anonymous" 
                onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} onEnded={handleAudioEnded} 
                className="hidden" 
            />
          )}
      </div>

      {/* 3. MAIN CONTENT AREA */}
      <div className="flex-1 overflow-hidden rounded-lg border border-zinc-800 bg-[#050505] relative flex flex-col hud-border shadow-lg mt-0">
         <div className="flex shrink-0 border-b border-zinc-800 bg-[#0a0a0c]/90 backdrop-blur-md z-10 w-full flex-col">
            <div className="flex items-center justify-between p-2">
                 <div className="flex items-center gap-2">
                    <button onClick={() => changePage(-1)} disabled={!canPrev} className="p-1.5 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] hover:text-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all"><ChevronLeft size={14} /></button>
                    <div className="text-center min-w-[60px]"><h3 className="text-[10px] font-bold text-[#00f3ff] uppercase tracking-widest font-tech">PG.{String(currentPage + 1).padStart(2,'0')}</h3></div>
                    <button onClick={() => changePage(1)} disabled={!canNext} className="p-1.5 rounded-sm bg-zinc-900 border border-zinc-800 hover:border-[#00f3ff] hover:text-[#00f3ff] text-zinc-400 disabled:opacity-30 transition-all"><ChevronRight size={14} /></button>
                </div>

                 {/* Centered Search */}
                 <div className="flex items-center gap-2 bg-zinc-950 border border-zinc-900 px-3 py-1 rounded-sm mx-auto flex-1 max-w-sm focus-within:border-[#00f3ff]/50 transition-colors">
                    <Search size={12} className="text-zinc-600" />
                    <input 
                        type="text" placeholder="SEARCH_TEXT..." value={searchQuery} 
                        onChange={(e) => setSearchQuery(e.target.value)} 
                        className="bg-transparent text-[10px] text-[#00f3ff] focus:outline-none w-full font-mono placeholder:text-zinc-700 uppercase text-center" 
                    />
                 </div>

                 <div className="flex items-center gap-2">
                    <button onClick={() => setViewMode(viewMode === 'split' ? 'single' : 'split')} className={`flex items-center gap-1 px-2 py-1 rounded-sm text-[9px] font-bold font-tech transition-all border ${viewMode === 'split' ? 'bg-[#00f3ff]/10 border-[#00f3ff] text-[#00f3ff]' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
                        {viewMode === 'split' ? <SplitSquareHorizontal size={12} /> : <Columns size={12} />} SPLIT
                    </button>
                    <button onClick={() => setAutoScroll(!autoScroll)} className={`flex items-center gap-1 px-2 py-1 rounded-sm text-[9px] font-bold font-tech transition-all border ${autoScroll ? 'bg-emerald-900/20 border-emerald-500 text-emerald-400' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
                        {autoScroll ? <Eye size={12} /> : <EyeOff size={12} />} TRACK
                    </button>
                 </div>
            </div>
         </div>

         <div className="flex-1 overflow-y-auto scroll-smooth custom-scrollbar relative p-4 pb-48">
             <div className={`flex flex-col gap-8 ${viewMode === 'split' ? '' : 'items-center'}`}>
                {paragraphData.map((para, pIdx) => (
                    <div key={pIdx} className={`w-full ${viewMode === 'split' ? 'flex' : 'max-w-4xl flex flex-col'} p-2`}>
                        <div className={`${viewMode === 'split' ? 'w-1/2 pr-6 border-r border-zinc-800/50' : 'w-full'} ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} text-zinc-400 whitespace-pre-wrap`}>
                            {para.original.map((sentence, sIdx) => {
                                const m = flatSentenceMap.find(sm => sm.pIndex === pIdx && sm.sIndex === sIdx);
                                const globalIdx = m?.globalIndex ?? -1;
                                const isActive = autoScroll && globalIdx === activeSentenceIndex;
                                return (
                                    <span key={sIdx} id={`original-sent-${globalIdx}`} className={`transition-all duration-300 px-[2px] ${isActive ? HIGHLIGHT_STYLES[settings.highlightColor] : 'hover:text-zinc-200'}`}>
                                        {highlightSearch(sentence)}{' '}
                                    </span>
                                );
                            })}
                        </div>
                        {viewMode === 'split' && (
                            <div className={`w-1/2 pl-6 ${TEXT_SIZES[settings.textSize]} ${LINE_HEIGHTS[settings.lineHeight]} text-zinc-500 whitespace-pre-wrap`}>
                                {para.translated.map((tSent, tIdx) => (
                                    <span key={tIdx} className="px-[2px]">{tSent}{' '}</span>
                                ))}
                            </div>
                        )}
                    </div>
                ))}
             </div>
         </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    // More robust line cleaning: remove markdown, empty lines, and handle possible extra characters
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);

    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;

    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;

      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();

      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];

    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);

    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });

    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }

    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;

    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);

      if (abortRef.current) return;

      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 128;
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  const handleTimeUpdate = () => {
    if (!audioRef.current) return;
    const { currentTime, duration } = audioRef.current;
    if (!duration) return;
    const currentPct = currentTime / duration;
    const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
    if (index !== -1 && index !== activeIndex) {
      setActiveIndex(index);
      segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate]);

  useEffect(() => {
    if (!isPlaying || !canvasRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const draw = () => {
      const bufferLength = analyserRef.current?.frequencyBinCount || 0;
      const dataArray = new Uint8Array(bufferLength);
      if (analyserRef.current) analyserRef.current.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const centerX = canvas.width / 2;
      const bars = bufferLength / 2;
      const step = canvas.width / 2 / bars;
      for (let i = 0; i < bars; i++) {
        const value = dataArray[i];
        const h = (value / 255) * canvas.height * 0.9;
        ctx.fillStyle = `rgb(${value}, ${243 - value}, 255)`;
        ctx.fillRect(centerX + (i * step), (canvas.height - h) / 2, step - 2, h);
        ctx.fillRect(centerX - ((i + 1) * step), (canvas.height - h) / 2, step - 2, h);
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const renderButtonLabel = () => {
    if (isLoading) return "STOP";
    if (hasInitiated) return "REGENERATE";
    return "INITIATE";
  };

  const renderButtonIcon = () => {
    if (isLoading) return <Square size={14} fill="currentColor" />;
    if (hasInitiated) return <RefreshCw size={14} />;
    return <Play size={14} fill="currentColor" />;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden">
       {/* Control Header - Dynamic (Full width) */}
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
              <div className="hidden md:flex items-center gap-3 text-[10px] font-mono border-l border-zinc-800 pl-4 uppercase">
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">HOST:</span>
                    <span className="text-cyan-400 font-bold">{hosts.host1.toUpperCase()}</span>
                 </div>
                 <div className="text-zinc-700">|</div>
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">CO-HOST:</span>
                    <span className="text-[#ff003c] font-bold">{hosts.host2.toUpperCase()}</span>
                 </div>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-24 bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-24 bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {renderButtonIcon()}
                 {renderButtonLabel()}
              </button>
          </div>
       </div>

       {/* Module Container - Dynamic (Full width) */}
       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           {/* Visualizer Player Box */}
           <div className="bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 h-[277px] flex flex-col shadow-2xl">
               <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                  <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

                  {/* Centered Episode Title Overlay */}
                  {audioSrc && !isLoading && episodeTitle && (
                    <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                        <div className="bg-black/70 backdrop-blur-md border border-zinc-800/50 px-6 py-3 rounded-sm shadow-[0_0_40px_rgba(0,0,0,0.9)] border-cyan-500/20 max-w-[85%]">
                           <span className="text-sm font-bold text-cyan-400 font-tech uppercase tracking-[0.3em] opacity-95 whitespace-normal text-center block leading-relaxed drop-shadow-[0_0_8px_rgba(0,243,255,0.6)]">EPISODE: {episodeTitle.toUpperCase()}</span>
                        </div>
                    </div>
                  )}

                  {isLoading ? (
                    <div className="z-20 scale-75 animate-fade-in">
                      <Loader text="SYNTHESIZING_COMM_LINK..." />
                    </div>
                  ) : audioSrc ? (
                    <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                  ) : (
                    <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                      <Activity size={32} className="opacity-20" />
                      <span>AWAITING_STREAM</span>
                    </div>
                  )}
               </div>

               {/* Player Controls Bar */}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2">
                       <button 
                         onClick={downloadScript}
                         disabled={!script}
                         className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`}
                         title="Download Script"
                       >
                           <FileDown size={20} />
                       </button>
                       <a 
                         href={audioSrc || '#'} 
                         download={`podcast-${chapter.id}.wav`} 
                         className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} 
                         onClick={(e) => !audioSrc && e.preventDefault()}
                         title="Download Audio"
                       >
                           <Download size={20} />
                       </a>
                   </div>
               </div>
           </div>

           <audio ref={audioRef} src={audioSrc || undefined} onTimeUpdate={handleTimeUpdate} onEnded={() => setIsPlaying(false)} className="hidden" />

           {/* Live Stream Script Module - Dynamic (Full width) */}
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();

                      // Strict matching for host identification
                      const isHost1 = cur === h1 || cur.includes(h1);
                      const isHost2 = cur === h2 || cur.includes(h2);

                      // Enforce Host 1 on Left, Host 2 on Right
                      const leftAligned = isHost1;

                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_15px_rgba(6,182,212,0.1)]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_15px_rgba(255,0,60,0.1)]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>
                                    {seg.speaker}
                                </div>
                                <p className={`leading-relaxed ${isActive ? 'text-white' : 'text-zinc-400'}`}>{seg.text}</p>

                                {/* Side Indicator matching bubble side */}
                                {isActive && (
                                    <div className={`absolute top-1/2 -translate-y-1/2 w-1 h-1/2 ${leftAligned ? '-left-1 bg-cyan-500' : '-right-1 bg-[#ff003c]'}`}></div>
                                )}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}

           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, RotateCcw, RotateCw, Mic2, Download, FileDown, Settings2, Activity, Radio, Globe, Square, Loader as LoaderIcon, AlertCircle, RefreshCw } from 'lucide-react';
import { generatePodcastAudio } from '../services/gemini';
import { Chapter, FileContext, AppSettings } from '../types';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
  settings: AppSettings;
}

interface ScriptSegment {
  speaker: string;
  text: string;
  startPct: number;
  endPct: number;
}

const TONES = ['Engaging', 'Aggressive', 'Incisive', 'Humorous', 'Instructive', 'Cyber-Noir', 'Sarcastic', 'Philosophical', 'Debate', 'Street-Samurai', 'Corpo-Rat', 'Netrunner'];

const LANGUAGES = [
  'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

const HOST_CONFIG: Record<string, { host1: string, voice1: string, host2: string, voice2: string }> = {
  'Engaging': { host1: 'Alex', voice1: 'Puck', host2: 'Jordan', voice2: 'Kore' },
  'Aggressive': { host1: 'Titan', voice1: 'Fenrir', host2: 'Viper', voice2: 'Charon' },
  'Incisive': { host1: 'Cipher', voice1: 'Puck', host2: 'Oracle', voice2: 'Kore' },
  'Humorous': { host1: 'Jester', voice1: 'Fenrir', host2: 'Pixel', voice2: 'Puck' },
  'Instructive': { host1: 'Professor', voice1: 'Kore', host2: 'Student', voice2: 'Zephyr' },
  'Cyber-Noir': { host1: 'Detective', voice1: 'Fenrir', host2: 'Client', voice2: 'Kore' },
  'Sarcastic': { host1: 'Glitch', voice1: 'Puck', host2: 'System', voice2: 'Kore' },
  'Philosophical': { host1: 'Sage', voice1: 'Charon', host2: 'Seeker', voice2: 'Zephyr' },
  'Debate': { host1: 'Pro', voice1: 'Puck', host2: 'Con', voice2: 'Fenrir' },
  'Street-Samurai': { host1: 'Ronin', voice1: 'Fenrir', host2: 'Katana', voice2: 'Kore' },
  'Corpo-Rat': { host1: 'Exec', voice1: 'Charon', host2: 'Assistant', voice2: 'Puck' },
  'Netrunner': { host1: 'Zero', voice1: 'Puck', host2: 'One', voice2: 'Kore' },
};

export const PodcastPlayer: React.FC<Props> = ({ chapter, fileContext, settings }) => {
  const [audioSrc, setAudioSrc] = useState<string | null>(null);
  const [episodeTitle, setEpisodeTitle] = useState<string>('');
  const [script, setScript] = useState<string | null>(null);
  const [segments, setSegments] = useState<ScriptSegment[]>([]);
  const [activeIndex, setActiveIndex] = useState<number>(-1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedTone, setSelectedTone] = useState('Engaging');
  const [selectedLanguage, setSelectedLanguage] = useState(settings.targetLanguage);
  const [playbackRate, setPlaybackRate] = useState(1.0);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').map(l => l.replace(/^\*\*|\*\*$/g, '').trim()).filter(line => line.length > 0);

    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;

    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;

      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();

      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];

    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);

    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });

    setSegments(parsed);
  }, [script]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }

    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;

    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);

      if (abortRef.current) return;

      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setEpisodeTitle(result.episodeTitle || chapter.title);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 128;
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate]);

  useEffect(() => {
    if (!isPlaying || !audioRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }

    const audio = audioRef.current;
    const draw = () => {
      // 1. High-frequency sync logic (independent of onTimeUpdate)
      if (audio && audio.duration) {
        const currentPct = audio.currentTime / audio.duration;
        const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
        if (index !== -1 && index !== activeIndex) {
          setActiveIndex(index);
          // Using block: 'center' to keep the conversation focus in the middle
          segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }

      // 2. Visualizer logic
      if (canvasRef.current && analyserRef.current) {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const bufferLength = analyserRef.current.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);
          analyserRef.current.getByteFrequencyData(dataArray);
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          const centerX = canvas.width / 2;
          const bars = bufferLength / 2;
          const step = canvas.width / 2 / bars;
          for (let i = 0; i < bars; i++) {
            const value = dataArray[i];
            const h = (value / 255) * canvas.height * 0.9;
            ctx.fillStyle = `rgb(${value}, ${243 - value}, 255)`;
            ctx.fillRect(centerX + (i * step), (canvas.height - h) / 2, step - 2, h);
            ctx.fillRect(centerX - ((i + 1) * step), (canvas.height - h) / 2, step - 2, h);
          }
        }
      }

      animationRef.current = requestAnimationFrame(draw);
    };

    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, segments, activeIndex]);

  const downloadScript = () => {
    if (!script) return;
    const blob = new Blob([script], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `podcast-script-${chapter.id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const renderButtonLabel = () => {
    if (isLoading) return "STOP";
    if (hasInitiated) return "REGENERATE";
    return "INITIATE";
  };

  const renderButtonIcon = () => {
    if (isLoading) return <Square size={14} fill="currentColor" />;
    if (hasInitiated) return <RefreshCw size={14} />;
    return <Play size={14} fill="currentColor" />;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 overflow-hidden">
       {/* Control Header */}
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
              <div className="hidden md:flex items-center gap-3 text-[10px] font-mono border-l border-zinc-800 pl-4 uppercase">
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">HOST:</span>
                    <span className="text-cyan-400 font-bold">{hosts.host1.toUpperCase()}</span>
                 </div>
                 <div className="text-zinc-700">|</div>
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">CO-HOST:</span>
                    <span className="text-[#ff003c] font-bold">{hosts.host2.toUpperCase()}</span>
                 </div>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-24 bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-24 bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {renderButtonIcon()}
                 {renderButtonLabel()}
              </button>
          </div>
       </div>

       {/* Module Container */}
       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full">
           {/* Visualizer Player Box */}
           <div className="bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 h-[277px] flex flex-col shadow-2xl">
               <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                  <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

                  {audioSrc && !isLoading && episodeTitle && (
                    <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none animate-fade-in">
                        <div className="bg-black/70 backdrop-blur-md border border-zinc-800/50 px-6 py-3 rounded-sm shadow-[0_0_40px_rgba(0,0,0,0.9)] border-cyan-500/20 max-w-[85%]">
                           <span className="text-sm font-bold text-cyan-400 font-tech uppercase tracking-[0.3em] opacity-95 whitespace-normal text-center block leading-relaxed drop-shadow-[0_0_8px_rgba(0,243,255,0.6)]">EPISODE: {episodeTitle.toUpperCase()}</span>
                        </div>
                    </div>
                  )}

                  {isLoading ? (
                    <div className="z-20 scale-75 animate-fade-in">
                      <Loader text="SYNTHESIZING_COMM_LINK..." />
                    </div>
                  ) : audioSrc ? (
                    <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                  ) : (
                    <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                      <Activity size={32} className="opacity-20" />
                      <span>AWAITING_STREAM</span>
                    </div>
                  )}
               </div>

               {/* Player Controls Bar */}
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-3 text-[10px] font-mono uppercase overflow-hidden">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(2)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end gap-2">
                       <button 
                         onClick={downloadScript}
                         disabled={!script}
                         className={`p-2 text-zinc-600 transition-colors rounded-full ${script ? 'hover:text-[#00f3ff] hover:bg-zinc-900' : 'opacity-30'}`}
                         title="Download Script"
                       >
                           <FileDown size={20} />
                       </button>
                       <a 
                         href={audioSrc || '#'} 
                         download={`podcast-${chapter.id}.wav`} 
                         className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} 
                         onClick={(e) => !audioSrc && e.preventDefault()}
                         title="Download Audio"
                       >
                           <Download size={20} />
                       </a>
                   </div>
               </div>
           </div>

           <audio ref={audioRef} src={audioSrc || undefined} onEnded={() => setIsPlaying(false)} className="hidden" />

           {/* Live Stream Script Module */}
           {segments.length > 0 ? (
               <div className="flex-1 min-h-0 bg-black/40 border border-zinc-800 rounded-lg overflow-hidden flex flex-col shadow-inner">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();

                      const isHost1 = cur === h1 || cur.includes(h1);
                      const isHost2 = cur === h2 || cur.includes(h2);

                      // Enforce Host 1 on Left, Host 2 on Right
                      const leftAligned = isHost1;

                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[85%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(6,182,212,0.3)] scale-[1.02]' : 'bg-rose-950/20 border-[#ff003c] shadow-[0_0_20px_rgba(255,0,60,0.3)] scale-[1.02]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>
                                    {seg.speaker}
                                </div>
                                <p className={`leading-relaxed transition-colors duration-300 ${isActive ? 'text-white font-medium' : 'text-zinc-400'}`}>{seg.text}</p>

                                {isActive && (
                                    <div className={`absolute top-1/2 -translate-y-1/2 w-1.5 h-1/2 rounded-full ${leftAligned ? '-left-0.5 bg-cyan-500 shadow-[0_0_10px_#00f3ff]' : '-right-0.5 bg-[#ff003c] shadow-[0_0_10px_#ff003c]'}`}></div>
                                )}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="flex-1 bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono min-h-[200px]">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}

           {error && (
               <div className="flex-1 bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono min-h-[200px]">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import { GoogleGenAI, Type, Modality, Chat, Content } from "@google/genai";
import { BookStructure, Chapter, Concept, DictionaryEntry, FileContext } from "../types";

const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const cleanGenAiText = (text: string): string => {
  if (!text) return "";
  return text
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`/g, '')
    .replace(/^#+\s/gm, '') 
    .trim();
};

const withRetry = async <T>(fn: () => Promise<T>, retries = 5, delay = 3000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const getErrorDetails = (e: any) => {
        if (e.error && typeof e.error === 'object') return e.error;
        if (e.response?.data?.error) return e.response.data.error;
        return e;
    };
    const details = getErrorDetails(error);
    const code = details.code || details.status || error.status || error.code;
    const message = String(details.message || error.message || JSON.stringify(error)).toLowerCase();
    const status = String(details.status || "").toLowerCase();

    const isNetworkError = message.includes('xhr') || message.includes('fetch') || message.includes('network');
    const numericCode = Number(code);
    const isServerError = (numericCode >= 500 && numericCode < 600) || status.includes('internal_server_error');
    const isRateLimit = numericCode === 429 || message.includes('429') || message.includes('quota') || status.includes('resource_exhausted');

    if (retries > 0 && (isNetworkError || isServerError || isRateLimit)) {
      let nextDelay = isRateLimit ? Math.max(delay, 15000) * 1.5 : delay * 2;
      nextDelay = Math.min(nextDelay, 180000) + (Math.random() * 2000); 
      console.warn(`Gemini API request failed (${code}). Retrying in ${Math.round(nextDelay/1000)}s...`);
      await new Promise(resolve => setTimeout(resolve, nextDelay));
      return withRetry(fn, retries - 1, nextDelay);
    }
    if (typeof error === 'object' && !error.message && details.message) throw new Error(details.message);
    throw error;
  }
};

const getFilePart = (file: FileContext) => {
  if (file.isText) return { text: file.content };
  return { inlineData: { mimeType: file.mimeType, data: file.content } };
};

export const analyzeBookStructure = async (file: FileContext): Promise<BookStructure> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: "Analyze this book content. Extract the book title, author, and a list of chapters. For each chapter, provide a title and a one-sentence description. If the content is short, divide it into logical sections. Provide a UNIQUE list of chapters. Return strictly JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["id", "title"]
              }
            }
          },
          required: ["title", "author", "chapters"]
        }
      }
    });
    if (!response.text) throw new Error("Failed to analyze book structure");
    const data = JSON.parse(response.text);
    return { ...data, id: crypto.randomUUID(), bookmarks: [] } as BookStructure;
  }, 5, 8000);
};

interface HostConfig {
  host1: string;
  voice1: string;
  host2: string;
  voice2: string;
}

export const generatePodcastAudio = async (
  file: FileContext,
  chapter: Chapter,
  tone: string = 'Engaging',
  hosts: HostConfig,
  language: string = 'English'
): Promise<{ audio: string; script: string; episodeTitle: string }> => {
  return withRetry(async () => {
    const ai = getAi();
    const scriptResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Create a ${tone} podcast conversation discussing the content of "${chapter.title}". 

          Speakers: ${hosts.host1} (Main Host) and ${hosts.host2} (Co-Host).

          CRITICAL INSTRUCTIONS:
          1. START the script IMMEDIATELY with the first host speaking.
          2. DO NOT include music cues or bracketed actions.
          3. EVERY LINE must follow the format: "SpeakerName: Dialogue".
          4. NO extra labels, brackets, or formatting outside of "SpeakerName: Dialogue".
          5. Use exactly these speaker names: "${hosts.host1}" and "${hosts.host2}".
          6. Ensure the dialogue feels natural and conversational.
          7. Language: ${language}.
          8. Length: Approx 2 minutes.
          9. Also provide a catchy, short summary title for this specific episode (max 6 words).` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            episodeTitle: { type: Type.STRING },
            script: { type: Type.STRING }
          },
          required: ["episodeTitle", "script"]
        }
      }
    });

    const parsedResponse = JSON.parse(scriptResponse.text || "{}");
    const script = parsedResponse.script;
    const episodeTitle = parsedResponse.episodeTitle;

    if (!script) throw new Error("Failed to generate script");

    const audioResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: script }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              { speaker: hosts.host1, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice1 } } },
              { speaker: hosts.host2, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice2 } } }
            ]
          }
        }
      }
    });
    const base64Audio = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Failed to generate audio content");
    return { audio: base64Audio, script, episodeTitle };
  }, 6, 8000);
};

